-- Poems batch 483
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-46','謝李若沖','張太華','唐','御定全唐诗','yuding','','[]','符吏匆匆叩夜扃，便隨金簡出幽冥。',32,'御定全唐詩/json/866.json','["符吏匆匆叩夜扃，便隨金簡出幽冥。", "蒙師薦拔恩非淺，領得生神九過經。"]'),
('yuding-47','幽恨詩','安邑坊女','唐','御定全唐诗','yuding','','[]','蔔得上峽日，秋江風浪多。巴陵一夜雨，腸斷木蘭歌。',24,'御定全唐詩/json/866.json','["蔔得上峽日，秋江風浪多。巴陵一夜雨，腸斷木蘭歌。"]'),
('yuding-48','和檢詩','韋檢亡姬','唐','御定全唐诗','yuding','','[]','春雨濛濛不見天，家家門外柳和煙。',32,'御定全唐詩/json/866.json','["春雨濛濛不見天，家家門外柳和煙。", "如今腸斷空垂淚，歡笑重追別有年。"]'),
('yuding-49','附：檢悼亡姬詩','韋檢','唐','御定全唐诗','yuding','','[]','寶劍化龍歸碧落，嫦娥隨月下黃泉。',32,'御定全唐詩/json/866.json','["寶劍化龍歸碧落，嫦娥隨月下黃泉。", "一杯酒向青春晚，寂寞書窗恨獨眠。"]'),
('yuding-50','夢後自題','韋檢','唐','御定全唐诗','yuding','','[]','白浪漫漫去不回，浮雲飛盡日西頹。',32,'御定全唐詩/json/866.json','["白浪漫漫去不回，浮雲飛盡日西頹。", "始皇陵上千年樹，銀鴨金鳧也變灰。"]'),
('yuding-51','與夫同詠詩','蘇檢妻','唐','御定全唐诗','yuding','','[]','楚水準如鏡，周回白鳥飛。金陵幾多地，一去不知歸。',24,'御定全唐詩/json/866.json','["楚水準如鏡，周回白鳥飛。金陵幾多地，一去不知歸。"]'),
('yuding-52','與夫同詠詩','蘇檢','唐','御定全唐诗','yuding','','[]','還吳東去過澄城，樓上清風酒半醒。',32,'御定全唐詩/json/866.json','["還吳東去過澄城，樓上清風酒半醒。", "想得到家春已暮，海棠千樹已凋零。"]'),
('yuding-53','冥會詩','宮嬪','唐','御定全唐诗','yuding','','[]','爭不逢人話此身，此身長夜不知春。',128,'御定全唐詩/json/866.json','["爭不逢人話此身，此身長夜不知春。", "自從國破家亡後，隴上惟添芳草新。", "休說人間恨戀多，況逢佳客此相過。", "堂中縱有千般樂，爭及陽春一曲歌。", "幽谷窮花似妾身，縱懷香豔吐無因。", "多情公子能相訪，應解回風暫借春。", "恩情未足曉光催，數朵眠花未得開。", "卻羨一雙金扼臂，得隨人世出將來。"]'),
('yuding-54','與謝翱贈答詩','金車美人','唐','御定全唐诗','yuding','','[]','陽臺後會杳無期，碧樹煙深玉漏遲。',144,'御定全唐詩/json/866.json','["陽臺後會杳無期，碧樹煙深玉漏遲。", "半夜香風滿庭月，花前空賦別離詩。", "相思無路莫相思，風裏花開只片時。", "惆悵金閨卻歸去，曉鶯啼斷綠楊枝。", "一紙華箋灑碧雲，餘香猶在墨猶新。空添滿目淒涼事，", "紅閨更有堪愁處，窗上蟲絲幾上塵。", "惆悵佳期一夢中，武陵春色盡成空。欲知離別偏堪恨，", "雙輪暫與王孫駐，明日西馳又向東。"]'),
('yuding-55','贈朋詩','魏朋妻','唐','御定全唐诗','yuding','','[]','孤墳臨清江，每睹白日晚。松影搖長風，蟾光落岩甸。',72,'御定全唐詩/json/866.json','["孤墳臨清江，每睹白日晚。松影搖長風，蟾光落岩甸。", "故鄉千里餘，親戚罕相見。望望空雲山，哀哀淚如霰。", "恨為泉台客，複此異鄉縣。願言敦疇昔，勿以棄疵賤。"]'),
('yuding-56','題明月堂二首','劉氏亡婦','唐','御定全唐诗','yuding','','[]','蟬鬢驚秋華髮新，可憐紅隙盡埃塵。',64,'御定全唐詩/json/866.json','["蟬鬢驚秋華髮新，可憐紅隙盡埃塵。", "西山一夢何年覺，明月堂前不見人。", "玉鉤風急響丁東，回首西山似夢中。", "明月堂前人不到，庭前一夜老秋風。"]'),
('yuding-57','詩','故台城妓','唐','御定全唐诗','yuding','','[]','歌罷玉樓月，舞殘金縷衣。勻鈿收迸節，斂黛別重闈。',48,'御定全唐詩/json/866.json','["歌罷玉樓月，舞殘金縷衣。勻鈿收迸節，斂黛別重闈。", "網斷蛛猶織，梁春燕不歸。那堪回首處，江步野棠飛。"]'),
('yuding-58','金陵詞','故台城妓','唐','御定全唐诗','yuding','','[]','宮中細草香紅濕，宮內纖腰碧窗泣。',32,'御定全唐詩/json/866.json','["宮中細草香紅濕，宮內纖腰碧窗泣。", "唯有虹梁春燕雛，猶傍珠簾玉鉤立。"]'),
('yuding-59','示宋善威','無名女鬼','唐','御定全唐诗','yuding','','[]','月落三株樹，日映九重天。良夜歡宴罷，暫別庚申年。',24,'御定全唐詩/json/866.json','["月落三株樹，日映九重天。良夜歡宴罷，暫別庚申年。"]'),
('yuding-60','詩','無名鬼','唐','御定全唐诗','yuding','','[]','江上檣竿一百尺，山中樓臺十二重。',64,'御定全唐詩/json/866.json','["江上檣竿一百尺，山中樓臺十二重。", "山僧樓上望江上，指點檣竿笑殺儂。", "仙人未必便仙去，還在人間人不知。", "手把白須從兩鹿，相逢卻問姓名誰。"]'),
('yuding-61','句','穠華','唐','御定全唐诗','yuding','','[]','柏堂新成樂未央，回來回去繞裴郎。',16,'御定全唐詩/json/866.json','["柏堂新成樂未央，回來回去繞裴郎。"]'),
('yuding-62','句','張守中','唐','御定全唐诗','yuding','','[]','薄命蘇秦頻去國，多情潘嶽旋興悲。',32,'御定全唐詩/json/866.json','["薄命蘇秦頻去國，多情潘嶽旋興悲。", "今夜若棲芳草徑，為傳幽意達王孫。"]'),
('yuding-63','句','無名鬼','唐','御定全唐诗','yuding','','[]','芫花半落，松風晚清。',10,'御定全唐詩/json/866.json','["芫花半落，松風晚清。"]'),
('yuding-0','渾家門客聯句','不詳','唐','御定全唐诗','yuding','','[]','自與渾家鄰，馨香遂滿身。無心好清靜，人用去灰塵。——麻大',70,'御定全唐詩/json/867.json','["自與渾家鄰，馨香遂滿身。無心好清靜，人用去灰塵。——麻大", "終朝每去依煙火，春至還歸養子孫。——和且耶", "曾向苻王筆端坐，爾來求食渾家門。——和且耶"]'),
('yuding-1','長須國駙馬詠妻','長須國駙馬','唐','御定全唐诗','yuding','','[]','花無葉不妍，女無須亦醜。丈人試遣惣無，未必不如惣有。',26,'御定全唐詩/json/867.json','["花無葉不妍，女無須亦醜。丈人試遣惣無，未必不如惣有。"]'),
('yuding-2','原陵老翁吟','原陵老翁','唐','御定全唐诗','yuding','','[]','野田荊棘春，閨閣綺羅新。出沒頭上日，生死眼前人。',196,'御定全唐詩/json/867.json','["野田荊棘春，閨閣綺羅新。出沒頭上日，生死眼前人。", "欲知我家在何處，北邙松柏正為鄰。", "洛陽女兒羅綺多，無奈孤翁老去何，奈爾何。", "正色鴻燾，神思化伐。穹施後承，光負玄設。嘔淪吐萌，", "拿尾研動。袾袾哳哳。dS用秘功，以嶺以穴。", "柂薪伐藥，莽榤萬茁。嘔律則祥，佛倫惟薩。牡虛無有，", "五行七曜，成此閏餘。上帝降靈，歲且涒徐。蛇蛻其皮，", "何以蔽踝，霞袂雲袽。哀爾浮生，櫛比荒墟。", "吾複麗氣，還形之初。在帝左右，道濟忽諸。"]'),
('yuding-3','述懷','嚴含質','唐','御定全唐诗','yuding','','[]','昔為仙子今為虎，流落陰崖足風雨。',32,'御定全唐詩/json/867.json','["昔為仙子今為虎，流落陰崖足風雨。", "更將斑毳被餘身，千載空山萬般苦。"]'),
('yuding-4','題壁','嚴含質','唐','御定全唐诗','yuding','','[]','下玄八千億甲子，丹飛先生嚴含質。謫下中天被斑革，',24,'御定全唐詩/json/867.json','["下玄八千億甲子，丹飛先生嚴含質。謫下中天被斑革，"]'),
('yuding-5','無題','李微','唐','御定全唐诗','yuding','','[]','偶因狂疾成殊類，災患相仍不可逃。今日爪牙誰敢敵，',40,'御定全唐詩/json/867.json','["偶因狂疾成殊類，災患相仍不可逃。今日爪牙誰敢敵，", "此夕溪山對明月，不成長嘯但成嗥。"]'),
('yuding-6','維揚空莊四怪聯句','不詳','唐','御定全唐诗','yuding','','[]','齊紈魯縞如霜雪，寥亮高聲予所發。——故杵',80,'御定全唐詩/json/867.json','["齊紈魯縞如霜雪，寥亮高聲予所發。——故杵", "嘉賓良會清夜時，煌煌燈燭我能持。——燈檯", "清冷之泉候朝汲，桑綆相牽常出入。——水桶", "爨薪貯泉相煎熬，充他口腹我為勞。——破鐺"]'),
('yuding-7','柳藏經二絕句','柳藏經','唐','御定全唐诗','yuding','','[]','寒水停園沼，秋池滿敗荷。杜門窮典籍，所得事今多。',48,'御定全唐詩/json/867.json','["寒水停園沼，秋池滿敗荷。杜門窮典籍，所得事今多。", "誰謂三才貴，余觀萬化同。心虛嫌蠹食，年老怯狂風。"]'),
('yuding-8','太白山魔誑道士詩','不詳','唐','御定全唐诗','yuding','','[]','三秋稽顙叩真靈，龍虎交時金液成。',32,'御定全唐詩/json/867.json','["三秋稽顙叩真靈，龍虎交時金液成。", "絳雪既凝身可度，蓬壺頂上彩雲生。"]'),
('yuding-9','金缶魅詩','不詳','唐','御定全唐诗','yuding','','[]','色分藍葉青，聲比磬中鳴。七月初七夜，吾當示汝形。',24,'御定全唐詩/json/867.json','["色分藍葉青，聲比磬中鳴。七月初七夜，吾當示汝形。"]'),
('yuding-10','東陽夜怪詩','不詳','唐','御定全唐诗','yuding','','[]','誰家掃雪滿庭前，萬壑千峰在一拳。',32,'御定全唐詩/json/867.json','["誰家掃雪滿庭前，萬壑千峰在一拳。", "吾心不覺侵衣冷，曾向此中居幾年。"]'),
('yuding-11','東陽夜怪詩','不詳','唐','御定全唐诗','yuding','','[]','擁褐藏名無定蹤，流沙千里度衰容。',64,'御定全唐詩/json/867.json','["擁褐藏名無定蹤，流沙千里度衰容。", "傳得南宗心地後，此身應便老雙峰。", "為有閻浮珍重因，遠離西國赴咸秦。", "自從無力休行道，且作頭陀不系身。"]'),
('yuding-12','東陽夜怪詩','不詳','唐','御定全唐诗','yuding','','[]','長安城東洛陽道，車輪不息塵浩浩。',64,'御定全唐詩/json/867.json','["長安城東洛陽道，車輪不息塵浩浩。", "爭利貪前競著鞭，相逢儘是塵中老。", "日晚長川不計程，離群獨步不能鳴。", "賴有青青河畔草，春來猶得慰羈情。"]'),
('yuding-13','東陽夜怪詩','不詳','唐','御定全唐诗','yuding','','[]','愛此飄颻六出公，輕瓊冷絮舞長空。',32,'御定全唐詩/json/867.json','["愛此飄颻六出公，輕瓊冷絮舞長空。", "當時正逐秦丞相，騰躑川原喜北風。"]'),
('yuding-14','東陽夜怪詩','不詳','唐','御定全唐诗','yuding','','[]','事君同樂義同憂，那校糟糠滿志休。',64,'御定全唐詩/json/867.json','["事君同樂義同憂，那校糟糠滿志休。", "不是守株空待兔，終當逐鹿出林丘。", "少年長負饑鷹用，內顧曾無寵鶴心。", "秋草驅除思去宇，平原毛血興從禽。"]'),
('yuding-15','東陽夜怪詩','不詳','唐','御定全唐诗','yuding','','[]','舞鏡爭鸞彩，臨場定鶻拳。正思仙仗日，翹首仰樓前。',72,'御定全唐詩/json/867.json','["舞鏡爭鸞彩，臨場定鶻拳。正思仙仗日，翹首仰樓前。", "養鬥形如木，迎春質似泥。信如風雨在，何憚跡卑棲。", "為脫田文難，常懷紀渻恩。欲知疏野態，霜曉叫荒村。"]'),
('yuding-16','東陽夜怪詩','不詳','唐','御定全唐诗','yuding','','[]','亂魯負虛名，游秦感寧生。候驚丞相喘，用識葛盧鳴。',48,'御定全唐詩/json/867.json','["亂魯負虛名，游秦感寧生。候驚丞相喘，用識葛盧鳴。", "黍稷滋農具，軒車乏道情。近來筋力退，一志在歸耕。"]'),
('yuding-17','東陽夜怪詩','不詳','唐','御定全唐诗','yuding','','[]','為慚食肉主恩深，日晏蟠蜿臥錦衾。',32,'御定全唐詩/json/867.json','["為慚食肉主恩深，日晏蟠蜿臥錦衾。", "且學志人知白黑，那將好爵動吾心。"]'),
('yuding-18','東陽夜怪詩','不詳','唐','御定全唐诗','yuding','','[]','鳥鼠是家川，周王昔獵賢。一從離子卯，應見海桑田。',24,'御定全唐詩/json/867.json','["鳥鼠是家川，周王昔獵賢。一從離子卯，應見海桑田。"]'),
('yuding-19','田四郎求婚聯句','不詳','唐','御定全唐诗','yuding','','[]','一點紅裳出翠微，秋天雲靜月離離。——田四郎',39,'御定全唐詩/json/867.json','["一點紅裳出翠微，秋天雲靜月離離。——田四郎", "天曹使者徒回首，何不從他九族卑。——"]'),
('yuding-20','黑駒別盧傳素詩','不詳','唐','御定全唐诗','yuding','','[]','既食丈人粟，又飽丈人芻。今日相償了，永離三惡途。',24,'御定全唐詩/json/867.json','["既食丈人粟，又飽丈人芻。今日相償了，永離三惡途。"]'),
('yuding-21','筆精詩','不詳','唐','御定全唐诗','yuding','','[]','昔荷蒙恬惠，尋遭仲叔投。夫君不指使，何處覓銀鉤。',80,'御定全唐詩/json/867.json','["昔荷蒙恬惠，尋遭仲叔投。夫君不指使，何處覓銀鉤。", "學問從君有，詩書自我傳。須知王逸少，名價動千年。", "能令音信通千里，解致龍蛇運八行。", "惆悵江生不相賞，應緣自負好文章。"]'),
('yuding-22','二斑與寧茵賦詩','不詳','唐','御定全唐诗','yuding','','[]','曉讀雲水靜，夜吟山月高。焉能履虎尾，豈用學牛刀。——甯茵',84,'御定全唐詩/json/867.json','["曉讀雲水靜，夜吟山月高。焉能履虎尾，豈用學牛刀。——甯茵", "但得居林嘯，焉能當路蹲。渡河何所適，終是怯劉琨。——斑寅", "無非悲甯戚，終是怯庖丁。若遇龔為守，蹄涔向北溟。——斑特"]'),
('yuding-23','白田獺魅別村女詩','不詳','唐','御定全唐诗','yuding','','[]','潮來逐潮上，潮落在空灘。有來終有去，情易複情難。',36,'御定全唐詩/json/867.json','["潮來逐潮上，潮落在空灘。有來終有去，情易複情難。", "腸斷腸中子，明月秋江寒。"]'),
('yuding-24','邢君才舊宅三怪詩','鐵銚','唐','御定全唐诗','yuding','','[]','昔日炎炎徒自知，今無烽灶欲何為。',32,'御定全唐詩/json/867.json','["昔日炎炎徒自知，今無烽灶欲何為。", "可憐國柄全無用，曾見家人下第時。"]'),
('yuding-25','邢君才舊宅三怪詩','破笛','唐','御定全唐诗','yuding','','[]','當時得意氣填心，一曲君前直萬金。',32,'御定全唐詩/json/867.json','["當時得意氣填心，一曲君前直萬金。", "今日不如庭下竹，風來猶得學龍吟。"]'),
('yuding-26','邢君才舊宅三怪詩','禿帚','唐','御定全唐诗','yuding','','[]','頭焦鬢禿但心存，力盡塵埃不復論。',32,'御定全唐詩/json/867.json','["頭焦鬢禿但心存，力盡塵埃不復論。", "莫笑今來同腐草，曾經終日掃朱門。"]'),
('yuding-27','維揚少年與孟氏贈答詩','孟氏','唐','御定全唐诗','yuding','','[]','可惜春時節，依然獨自遊。無端兩行淚，長只對花流。',24,'御定全唐詩/json/867.json','["可惜春時節，依然獨自遊。無端兩行淚，長只對花流。"]'),
('yuding-28','維揚少年與孟氏贈答詩','孟氏','唐','御定全唐诗','yuding','','[]','誰家少年兒，心中暗自欺。不道終不可，可即恐郎知。',24,'御定全唐詩/json/867.json','["誰家少年兒，心中暗自欺。不道終不可，可即恐郎知。"]'),
('yuding-29','維揚少年與孟氏贈答詩','少年','唐','御定全唐诗','yuding','','[]','神女得張碩，文君遇長卿。逢時兩相得，聊足慰多情。',24,'御定全唐詩/json/867.json','["神女得張碩，文君遇長卿。逢時兩相得，聊足慰多情。"]'),
('yuding-30','胡志忠題戶','不詳','唐','御定全唐诗','yuding','','[]','恃勇禍必嬰，恃強勢必傾。胡為萬金子，而與惡物爭。',40,'御定全唐詩/json/867.json','["恃勇禍必嬰，恃強勢必傾。胡為萬金子，而與惡物爭。", "休將逝魄趨府庭，止於此館歸冥冥。"]'),
('yuding-31','高侍郎詩','不詳','唐','御定全唐诗','yuding','','[]','危冠高袖楚宮妝，獨步閒庭逐夜涼。',32,'御定全唐詩/json/867.json','["危冠高袖楚宮妝，獨步閒庭逐夜涼。", "自把玉簪敲砌竹，清歌一曲月如霜。"]'),
('yuding-32','呂氏宅妖誓師詞','不詳','唐','御定全唐诗','yuding','','[]','天馬斜飛度三止，上將橫行擊四方。',32,'御定全唐詩/json/867.json','["天馬斜飛度三止，上將橫行擊四方。", "輜車直入無回翔，六甲次第不乖行。"]'),
('yuding-33','袁少年詩','不詳','唐','御定全唐诗','yuding','','[]','風波千里闊，台榭半天高。此興將何比，身知插羽毛。',72,'御定全唐詩/json/867.json','["風波千里闊，台榭半天高。此興將何比，身知插羽毛。", "峰巒多秀色，松桂足清聲。自有山林趣，全忘城闕情。", "羅浮南海外，昔日已聞之。千里來遊覽，幽情我自知。"]'),
('yuding-34','東柯院妖謔杜令','不詳','唐','御定全唐诗','yuding','','[]','雖共蒿蘭伍，南朝有宗祖。莫打綠袍人，空中且歌舞。',48,'御定全唐詩/json/867.json','["雖共蒿蘭伍，南朝有宗祖。莫打綠袍人，空中且歌舞。", "堪憐木邊土，非兒不似女。瘦馬上高山，登臨何自苦。"]'),
('yuding-35','嵩山小兒吟','不詳','唐','御定全唐诗','yuding','','[]','我本長生深山內，更何入他不二門。',32,'御定全唐詩/json/867.json','["我本長生深山內，更何入他不二門。", "爭如訪取舊時伴，休更朝夕勞神魂。"]'),
('yuding-36','魚腹丹書','不詳','唐','御定全唐诗','yuding','','[]','九登龍門山，三飲太湖水。畢竟不成龍，命負張鬍子。',24,'御定全唐詩/json/867.json','["九登龍門山，三飲太湖水。畢竟不成龍，命負張鬍子。"]'),
('yuding-37','魚身字','不詳','唐','御定全唐诗','yuding','','[]','三度過海，兩度上漢。行至勒漠，命屬柏君。',20,'御定全唐詩/json/867.json','["三度過海，兩度上漢。行至勒漠，命屬柏君。"]'),
('yuding-38','馬作人語','不詳','唐','御定全唐诗','yuding','','[]','蘆荻花，此花開後路無家。',12,'御定全唐詩/json/867.json','["蘆荻花，此花開後路無家。"]'),
('yuding-39','孫長史女與焦封贈答詩','孫長史女','唐','御定全唐诗','yuding','','[]','妾失鴛鴦伴，君方萍梗遊。少年歡醉後，只恐苦相留。',96,'御定全唐詩/json/867.json','["妾失鴛鴦伴，君方萍梗遊。少年歡醉後，只恐苦相留。", "心常名宦外，終不恥狂遊。誤入桃源裏，仙家爭肯留。", "鵲橋織女會，也是不多時。今日送君處，羞言連理枝。", "但保同心結，無勞織錦詩。蘇秦求富貴，自有一回時。"]'),
('yuding-40','石甕寺燈魅詩','不詳','唐','御定全唐诗','yuding','','[]','涼風暮起驪山空，長生殿鎖霜葉紅。',104,'御定全唐詩/json/867.json','["涼風暮起驪山空，長生殿鎖霜葉紅。", "朝來試入華清宮，分明憶得開元中。", "金殿不勝秋，月斜石樓冷。誰是相顧人，褰帷吊孤影。", "煙滅石樓空，悠悠永夜中。虛心怯秋雨，豔質畏飄風。", "向壁殘花碎，侵階墜葉紅。還如失群鶴，飲恨在雕籠。"]'),
('yuding-41','洛下女郎歌','不詳','唐','御定全唐诗','yuding','','[]','皎潔玉顏勝白雪，況乃當年對風月。',32,'御定全唐詩/json/867.json','["皎潔玉顏勝白雪，況乃當年對風月。", "沈吟不敢怨春風，自歎容華暗消歇。"]'),
('yuding-42','洛下女郎歌','不詳','唐','御定全唐诗','yuding','','[]','絳衣披拂露盈盈，淡染胭脂一朵輕。',32,'御定全唐詩/json/867.json','["絳衣披拂露盈盈，淡染胭脂一朵輕。", "自恨紅顏留不住，莫怨春風道薄情。"]'),
('yuding-43','袁長官女詩','不詳','唐','御定全唐诗','yuding','','[]','彼見是忘憂，此看同腐草。青山與白雲，方展我懷抱。',24,'御定全唐詩/json/867.json','["彼見是忘憂，此看同腐草。青山與白雲，方展我懷抱。"]'),
('yuding-44','袁長官女詩','不詳','唐','御定全唐诗','yuding','','[]','剛被恩情役此心，無端變化幾湮沈。',32,'御定全唐詩/json/867.json','["剛被恩情役此心，無端變化幾湮沈。", "不如逐伴歸山去，長笑一聲煙霧深。"]'),
('yuding-45','真符女與申屠澄贈和詩','不詳','唐','御定全唐诗','yuding','','[]','一尉慚梅福，三年愧孟光。此情何所喻，川上有鴛鴦。',24,'御定全唐詩/json/867.json','["一尉慚梅福，三年愧孟光。此情何所喻，川上有鴛鴦。"]'),
('yuding-46','真符女與申屠澄贈和詩','不詳','唐','御定全唐诗','yuding','','[]','琴瑟情雖重，山林志自深。常憂時節變，辜負百年心。',24,'御定全唐詩/json/867.json','["琴瑟情雖重，山林志自深。常憂時節變，辜負百年心。"]'),
('yuding-47','夭桃詩','不詳','唐','御定全唐诗','yuding','','[]','鉛華久禦向人間，欲舍鉛華更慘顏。',32,'御定全唐詩/json/867.json','["鉛華久禦向人間，欲舍鉛華更慘顏。", "縱有青丘吟夜月，無因重照舊雲鬟。"]'),
('yuding-48','青衣春條詩','不詳','唐','御定全唐诗','yuding','','[]','幽室鎖妖豔，無人蘭蕙芳。春風三十載，不盡羅衣香。',24,'御定全唐詩/json/867.json','["幽室鎖妖豔，無人蘭蕙芳。春風三十載，不盡羅衣香。"]'),
('yuding-49','明器婢詩','不詳','唐','御定全唐诗','yuding','','[]','獨持巾櫛掩玄關，小帳無人燭影殘。',32,'御定全唐詩/json/867.json','["獨持巾櫛掩玄關，小帳無人燭影殘。", "昔日羅衣今化盡，白楊風起隴頭寒。"]'),
('yuding-50','妙香詞','不詳','唐','御定全唐诗','yuding','','[]','勸君酒莫辭，花落拋舊枝。只有北邙山下月，',20,'御定全唐詩/json/867.json','["勸君酒莫辭，花落拋舊枝。只有北邙山下月，"]'),
('yuding-51','廬山女贈朱樸','不詳','唐','御定全唐诗','yuding','','[]','但持冰潔心，不識風霜冷。任是懷禮容，無人顧形影。',56,'御定全唐詩/json/867.json','["但持冰潔心，不識風霜冷。任是懷禮容，無人顧形影。", "知君久積池塘夢，遣我方思變動來。", "操執若同顏叔子，今宵寧免淚盈腮。"]'),
('yuding-52','青蘿帳女贈穆郎','不詳','唐','御定全唐诗','yuding','','[]','團圓今夕色光輝，結了同心翠帶垂。',32,'御定全唐詩/json/867.json','["團圓今夕色光輝，結了同心翠帶垂。", "此後莫教塵點染，他年長照歲寒姿。"]'),
('yuding-53','褰帳','不詳','唐','御定全唐诗','yuding','','[]','揉藍綠色曲塵開，靜見三星入坐來。',32,'御定全唐詩/json/867.json','["揉藍綠色曲塵開，靜見三星入坐來。", "桂影已圓攀折後，子孫長作棟樑材。"]'),
('yuding-54','題碧花箋','不詳','唐','御定全唐诗','yuding','','[]','珠露素中書繾綣，青蘿帳裏寄鴛鴦。',32,'御定全唐詩/json/867.json','["珠露素中書繾綣，青蘿帳裏寄鴛鴦。", "自憐孤影清秋夕，灑淚裴回滴冷光。"]'),
('yuding-55','白蘋洲碧衣女子吟','不詳','唐','御定全唐诗','yuding','','[]','碧水色堪染，白蓮香正濃。分飛俱有恨，此別幾時逢。',48,'御定全唐詩/json/867.json','["碧水色堪染，白蓮香正濃。分飛俱有恨，此別幾時逢。", "藕隱玲瓏玉，花藏縹緲容。何當假雙翼，聲影暫相從。"]'),
('yuding-56','新林驛女吟示歐陽訓','不詳','唐','御定全唐诗','yuding','','[]','月明階悄悄，影只腰身小。誰是鶱翔人，願為比翼鳥。',24,'御定全唐詩/json/867.json','["月明階悄悄，影只腰身小。誰是鶱翔人，願為比翼鳥。"]'),
('yuding-57','擊盤歌送歐陽訓酒','不詳','唐','御定全唐诗','yuding','','[]','飛燕身輕未是輕，枉將弱質在岩扃。',32,'御定全唐詩/json/867.json','["飛燕身輕未是輕，枉將弱質在岩扃。", "今來不得同鴛枕，相伴神魂入杳冥。"]'),
('yuding-58','白衣女子木葉上詩','不詳','唐','御定全唐诗','yuding','','[]','桃花洞口開，香蕊落莓苔。佳景雖堪玩，蕭郎殊未來。',24,'御定全唐詩/json/867.json','["桃花洞口開，香蕊落莓苔。佳景雖堪玩，蕭郎殊未來。"]'),
('yuding-59','席上歌','不詳','唐','御定全唐诗','yuding','','[]','洞府深沈春日長，山花無主自芬芳。',32,'御定全唐詩/json/867.json','["洞府深沈春日長，山花無主自芬芳。", "憑闌寂寂看明月，欲種桃花待阮郎。"]'),
('yuding-60','鳳凰台怪和歌四首','不詳','唐','御定全唐诗','yuding','','[]','深閨閑鎖難成夢，那得同衾共繡床。',128,'御定全唐詩/json/867.json','["深閨閑鎖難成夢，那得同衾共繡床。", "一自與郎江上別，霜天更自覺宵長。", "愁聽黃鶯喚友聲，空閨曙色夢初成。", "窗間總有花箋紙，難寄妾心字字明。", "寂靜璿閨度歲年，並頭蓮葉又如錢。", "愁人獨處那堪此，安得君來獨枕眠。", "臥病匡床香屢添，夜深猶有一絲煙。", "懷君無計能成夢，更恨砧聲到枕邊。"]'),
('yuding-0','夢丹書','李亨','唐','御定全唐诗','yuding','','[]','厥不雲乎，惟其惟時。上天所保，福祿不虧。',20,'御定全唐詩/json/868.json','["厥不雲乎，惟其惟時。上天所保，福祿不虧。"]'),
('yuding-1','夢黃衣童子歌','李豫','唐','御定全唐诗','yuding','','[]','中五之德方峨峨，胡胡呼呼何奈何。',16,'御定全唐詩/json/868.json','["中五之德方峨峨，胡胡呼呼何奈何。"]'),
('yuding-2','夢揚州樂妓和詩','劉禹錫','唐','御定全唐诗','yuding','','[]','花作嬋娟玉作妝，風流爭似舊徐娘。',32,'御定全唐詩/json/868.json','["花作嬋娟玉作妝，風流爭似舊徐娘。", "夜深曲曲灣灣月，萬里隨君一寸腸。"]'),
('yuding-3','夢中美人歌','邢鳳','唐','御定全唐诗','yuding','','[]','長安少女踏春陽，何處春陽不斷腸。',32,'御定全唐詩/json/868.json','["長安少女踏春陽，何處春陽不斷腸。", "舞袖弓彎渾忘卻，羅衣空換九秋霜。"]'),
('yuding-4','夢中詩','石季武','唐','御定全唐诗','yuding','','[]','聳轡排金闕，乘軒上漢槎。浮名何足戀，高舉入煙霞。',24,'御定全唐詩/json/868.json','["聳轡排金闕，乘軒上漢槎。浮名何足戀，高舉入煙霞。"]'),
('yuding-5','葬西施挽歌','王炎','唐','御定全唐诗','yuding','','[]','西望吳王國，雲書鳳字牌。連江起珠帳，擇地葬金釵。',48,'御定全唐詩/json/868.json','["西望吳王國，雲書鳳字牌。連江起珠帳，擇地葬金釵。", "滿地紅心草，三層碧玉階。春風無處所，淒恨不勝懷。"]'),
('yuding-6','秦夢詩三首：挽公主','沈亞之','唐','御定全唐诗','yuding','','[]','泣葬一枝紅，生同死不同。金鈿墜芳草，香繡滿春風。',48,'御定全唐詩/json/868.json','["泣葬一枝紅，生同死不同。金鈿墜芳草，香繡滿春風。", "舊日聞簫處，高樓當月中。梨花寒食夜，深閉翠微宮。"]'),
('yuding-7','秦夢詩三首：別穆公','沈亞之','唐','御定全唐诗','yuding','','[]','擊髆舞，恨滿煙光無處所。淚如雨，欲擬著辭不成語。',48,'御定全唐詩/json/868.json','["擊髆舞，恨滿煙光無處所。淚如雨，欲擬著辭不成語。", "金鳳銜紅舊繡衣，幾度宮中同看舞。人間春日正歡樂，"]'),
('yuding-8','秦夢詩三首：題宮門','沈亞之','唐','御定全唐诗','yuding','','[]','君王多感放東歸，從此秦宮不復期。',32,'御定全唐詩/json/868.json','["君王多感放東歸，從此秦宮不復期。", "春景似傷秦喪主，落花如雨淚燕脂。"]'),
('yuding-9','夢中詩','盧獻卿','唐','御定全唐诗','yuding','','[]','卜築郊原古，青山無四鄰。扶疏繞屋樹，寂寞獨歸人。',24,'御定全唐詩/json/868.json','["卜築郊原古，青山無四鄰。扶疏繞屋樹，寂寞獨歸人。"]'),
('yuding-10','夢為吳泰伯作勝兒歌','劉景複','唐','御定全唐诗','yuding','','[]','繁弦已停雜吹歇，勝兒調弄邏娑撥。四弦攏撚三五聲，',136,'御定全唐詩/json/868.json','["繁弦已停雜吹歇，勝兒調弄邏娑撥。四弦攏撚三五聲，", "小弦切切怨颸颸，鬼哭神悲秋窸窣。倒腕斜挑掣流電，", "我聞天寶十年前，涼州未作西戎窟。麻衣右衽皆漢民，", "玄宗未到萬里橋，東洛西京一時沒。漢土民皆沒為虜，", "國門之西八九鎮，高城深壘閉閑卒。河湟咫尺不能收，", "勝兒若向邊塞彈，征人淚血應闌幹。"]'),
('yuding-11','夢中辭','郭仁表','唐','御定全唐诗','yuding','','[]','飄風暴雨可思惟，鶴望巢門斂翅飛。吾道之宗正可依，',24,'御定全唐詩/json/868.json','["飄風暴雨可思惟，鶴望巢門斂翅飛。吾道之宗正可依，"]'),
('yuding-12','夢崔嘏妻詩','國邵南','唐','御定全唐诗','yuding','','[]','莫以真留妾，從他理管弦。容華難久駐，知得幾多年。',24,'御定全唐詩/json/868.json','["莫以真留妾，從他理管弦。容華難久駐，知得幾多年。"]'),
('yuding-13','夢白衣婦人歌詞','盧絳','唐','御定全唐诗','yuding','','[]','玉京人去秋蕭索，畫簷鵲起梧桐落。欹枕悄無言，',54,'御定全唐詩/json/868.json','["玉京人去秋蕭索，畫簷鵲起梧桐落。欹枕悄無言，", "清風明月夜深時，箕帚盧郎恨已遲。", "他日孟家坡上約，再來相見是佳期。"]'),
('yuding-14','夢舜撫琴歌','張生','唐','御定全唐诗','yuding','','[]','南風熏熏兮草芊芊，妙有之音兮歸清弦。',43,'御定全唐詩/json/868.json','["南風熏熏兮草芊芊，妙有之音兮歸清弦。", "蕩蕩之教兮由自然，熙熙之化兮吾道全，熏熏兮思何傳。"]'),
('yuding-15','夢康仙示詩','漳郡守','唐','御定全唐诗','yuding','','[]','賣藥因循未得還，卻因耽酒到人間。',32,'御定全唐詩/json/868.json','["賣藥因循未得還，卻因耽酒到人間。", "有心只戀琵琶阪，無意更登山上山。"]'),
('yuding-16','夢中歌','白氏','唐','御定全唐诗','yuding','','[]','今夕何夕，存耶沒耶？良人去兮天之涯，',18,'御定全唐詩/json/868.json','["今夕何夕，存耶沒耶？良人去兮天之涯，"]'),
('yuding-17','夢中歌','張生妻','唐','御定全唐诗','yuding','','[]','歎衰草，絡緯聲切切。良人一去不復還，',144,'御定全唐詩/json/868.json','["歎衰草，絡緯聲切切。良人一去不復還，", "勸君酒，君莫辭。落花徒繞枝，流水無返期。", "莫恃少年時，少年能幾時。", "怨空閨，秋日亦難暮。夫婿斷音書，遙天雁空度。", "切切夕風急，露滋庭草濕。良人去不回，焉知掩閨泣。", "螢火穿白楊，悲風入荒草。疑是夢中游，愁迷故園道。", "花前始相見，花下又相送。何必言夢中，人生盡如夢。"]'),
('yuding-18','夢王尚書口授吟','張氏女','唐','御定全唐诗','yuding','','[]','鬟梳鬧掃學宮妝，獨立閒庭納夜涼。',32,'御定全唐詩/json/868.json','["鬟梳鬧掃學宮妝，獨立閒庭納夜涼。", "手把玉簪敲砌竹，清歌一曲月如霜。"]'),
('yuding-19','歌','病狂人','唐','御定全唐诗','yuding','','[]','踏陽春，人間三月雨和塵。陽春踏，秋風起，',44,'御定全唐詩/json/868.json','["踏陽春，人間三月雨和塵。陽春踏，秋風起，", "五靈華，曉玲瓏，天府由來汝府中。惆悵此情言不盡，"]'),
('yuding-20','題禪窟蘭若','陳季卿','唐','御定全唐诗','yuding','','[]','霜鐘鳴時夕風急，亂鴉又望寒林集。',32,'御定全唐詩/json/868.json','["霜鐘鳴時夕風急，亂鴉又望寒林集。", "此時輟棹悲且吟，獨向蓮華一峰立。"]'),
('yuding-21','題潼關普通院門','陳季卿','唐','御定全唐诗','yuding','','[]','度關悲失志，萬緒亂心機。下阪馬無力，掃門塵滿衣。',48,'御定全唐詩/json/868.json','["度關悲失志，萬緒亂心機。下阪馬無力，掃門塵滿衣。", "計謀多不就，心口自相違。已作羞歸計，還勝羞不歸。"]'),
('yuding-22','江亭晚望題書齋','陳季卿','唐','御定全唐诗','yuding','','[]','立向江亭滿目愁，十年前事信悠悠。田園已逐浮雲散，',40,'御定全唐詩/json/868.json','["立向江亭滿目愁，十年前事信悠悠。田園已逐浮雲散，", "不緣齒發未遲暮，吟對遠山堪白頭。"]'),
('yuding-23','別妻','陳季卿','唐','御定全唐诗','yuding','','[]','月斜寒露白，此夕去留心。酒至添愁飲，詩成和淚吟。',48,'御定全唐詩/json/868.json','["月斜寒露白，此夕去留心。酒至添愁飲，詩成和淚吟。", "離歌淒鳳管，別鶴怨瑤琴。明夜相思處，秋風吹半衾。"]'),
('yuding-24','別兄弟','陳季卿','唐','御定全唐诗','yuding','','[]','謀身非不早，其奈命來遲。舊友皆霄漢，此身猶路岐。',48,'御定全唐詩/json/868.json','["謀身非不早，其奈命來遲。舊友皆霄漢，此身猶路岐。", "北風微雪後，晚景有雲時。惆悵清江上，區區趁試期。"]'),
('yuding-25','夢中句','周延翰','唐','御定全唐诗','yuding','','[]','紫髯之伴有丹砂。',8,'御定全唐詩/json/868.json','["紫髯之伴有丹砂。"]'),
('yuding-26','夢中和句','任玠','唐','御定全唐诗','yuding','','[]','故國路遙歸去來，春風天遠望不盡。',16,'御定全唐詩/json/868.json','["故國路遙歸去來，春風天遠望不盡。"]'),
('yuding-27','夢中語','杜牧','唐','御定全唐诗','yuding','','[]','辭春不及秋，昆腳與皆頭。',12,'御定全唐詩/json/868.json','["辭春不及秋，昆腳與皆頭。"]'),
('yuding-28','夢中詩','胥偃','唐','御定全唐诗','yuding','','[]','昔作樹頭花，今為塚中骨。',12,'御定全唐詩/json/868.json','["昔作樹頭花，今為塚中骨。"]'),
('yuding-29','夢中語','曾崇范妻','唐','御定全唐诗','yuding','','[]','田頭有鹿跡，由尾著日炙。',12,'御定全唐詩/json/868.json','["田頭有鹿跡，由尾著日炙。"]'),
('yuding-30','紀夢句','張孜','唐','御定全唐诗','yuding','','[]','上天知我憶其人，使向人間夢中見。',16,'御定全唐詩/json/868.json','["上天知我憶其人，使向人間夢中見。"]'),
('yuding-0','嘲蘇世長','李淵','唐','御定全唐诗','yuding','','[]','名長意短，口正心邪。棄忠貞于鄭國，忘信義於吾家。',24,'御定全唐詩/json/869.json','["名長意短，口正心邪。棄忠貞于鄭國，忘信義於吾家。"]'),
('yuding-1','戲題畫','李旦','唐','御定全唐诗','yuding','','[]','喚出眼，何用苦深藏。縮卻鼻，何畏不聞香。',20,'御定全唐詩/json/869.json','["喚出眼，何用苦深藏。縮卻鼻，何畏不聞香。"]'),
('yuding-2','嘲蕭瑀射','歐陽詢','唐','御定全唐诗','yuding','','[]','急風吹緩箭，弱手馭強弓。欲高翻複下，應西還更東。',48,'御定全唐詩/json/869.json','["急風吹緩箭，弱手馭強弓。欲高翻複下，應西還更東。", "十回俱著地，兩手並擎空。借問誰為此，乃應是宋公。"]'),
('yuding-3','與歐陽詢互嘲','長孫無忌','唐','御定全唐诗','yuding','','[]','聳膊成山字，埋肩不出頭。誰家麟角上，畫此一獼猴。',24,'御定全唐詩/json/869.json','["聳膊成山字，埋肩不出頭。誰家麟角上，畫此一獼猴。"]'),
('yuding-4','與歐陽詢互嘲','歐陽詢','唐','御定全唐诗','yuding','','[]','索頭連背暖，漫襠畏肚寒。只因心渾渾，所以麵團團。',24,'御定全唐詩/json/869.json','["索頭連背暖，漫襠畏肚寒。只因心渾渾，所以麵團團。"]'),
('yuding-5','為溫僕射嘲竹','裴略','唐','御定全唐诗','yuding','','[]','竹，風吹青肅肅。淩冬葉不凋，經春子不熟。',36,'御定全唐詩/json/869.json','["竹，風吹青肅肅。淩冬葉不凋，經春子不熟。", "虛心未得待國士，皮上何須生節目。"]'),
('yuding-6','又嘲屏牆','裴略','唐','御定全唐诗','yuding','','[]','高下八九尺，東西六七步。突兀當廳坐，幾許遮賢路。',24,'御定全唐詩/json/869.json','["高下八九尺，東西六七步。突兀當廳坐，幾許遮賢路。"]'),
('yuding-7','嘲崔左丞','省吏','唐','御定全唐诗','yuding','','[]','崔子曲如鉤，隨例得封侯。髆上全無項，胸前別有頭。',24,'御定全唐詩/json/869.json','["崔子曲如鉤，隨例得封侯。髆上全無項，胸前別有頭。"]'),
('yuding-8','嘲高士廉木履','選人','唐','御定全唐诗','yuding','','[]','刺鼻何曾嚏，蹋面不知嗔。高生兩個齒，自謂得勝人。',24,'御定全唐詩/json/869.json','["刺鼻何曾嚏，蹋面不知嗔。高生兩個齒，自謂得勝人。"]'),
('yuding-9','書化度藏院壁','裴玄智','唐','御定全唐诗','yuding','','[]','將肉遣狼守，置骨向狗頭。自非阿羅漢，焉能免得偷。',24,'御定全唐詩/json/869.json','["將肉遣狼守，置骨向狗頭。自非阿羅漢，焉能免得偷。"]'),
('yuding-10','嘲許子儒','竇昉','唐','御定全唐诗','yuding','','[]','不能專習禮，虛心強覓階。一年辭爵弁，半歲履麻鞋。',73,'御定全唐詩/json/869.json','["不能專習禮，虛心強覓階。一年辭爵弁，半歲履麻鞋。", "瓦惡頻蒙cv，牆虛屢被叉。映樹便側睡，過匱即放乖。", "歲暮良工畢，言是越朋儕。今日綸言降，方知愚計喎。"]'),
('yuding-11','與趙神德互嘲','梁寶','唐','御定全唐诗','yuding','','[]','趙神德，天上既無雲，閃電何以無準則？——梁寶',74,'御定全唐詩/json/869.json','["趙神德，天上既無雲，閃電何以無準則？——梁寶", "向者入門來，案後惟見一挺墨。——趙神德", "官裏料朱砂，半眼供一國。——梁寶", "磨公小拇指，塗得太社北。——趙神德"]'),
('yuding-12','與講師互謔','釋元康','唐','御定全唐诗','yuding','','[]','甘桃不結實，苦李壓低枝。——釋元康',33,'御定全唐詩/json/869.json','["甘桃不結實，苦李壓低枝。——釋元康", "輪王千個子，巷伯勿孫兒。——講師"]'),
('yuding-13','詠興善寺佛殿災','李榮','唐','御定全唐诗','yuding','','[]','道善何曾善，言興且不興。如來燒赤盡，惟有一群僧。',24,'御定全唐詩/json/869.json','["道善何曾善，言興且不興。如來燒赤盡，惟有一群僧。"]'),
('yuding-14','敘可笑事','張元一','唐','御定全唐诗','yuding','','[]','朱前疑著綠，逯仁傑著朱。閻知微騎馬，馬吉甫騎驢。',46,'御定全唐詩/json/869.json','["朱前疑著綠，逯仁傑著朱。閻知微騎馬，馬吉甫騎驢。", "將名作姓李千里，將姓作名吳棲梧。左台胡禦史，"]'),
('yuding-15','嘲武懿宗','張元一','唐','御定全唐诗','yuding','','[]','長弓短度箭，蜀馬臨階騙。去賊七百里，隈牆獨自戰。',37,'御定全唐詩/json/869.json','["長弓短度箭，蜀馬臨階騙。去賊七百里，隈牆獨自戰。", "忽然逢著賊，騎豬向南r2。"]'),
('yuding-16','又嘲','張元一','唐','御定全唐诗','yuding','','[]','裹頭極草草，掠鬢不菶菶。未見桃花面皮，漫作杏子眼孔。',26,'御定全唐詩/json/869.json','["裹頭極草草，掠鬢不菶菶。未見桃花面皮，漫作杏子眼孔。"]'),
('yuding-17','詠靜樂縣主','張元一','唐','御定全唐诗','yuding','','[]','馬帶桃花錦，裙銜綠草羅。定知幃帽底，儀容似大哥。',24,'御定全唐詩/json/869.json','["馬帶桃花錦，裙銜綠草羅。定知幃帽底，儀容似大哥。"]'),
('yuding-18','嘲格輔元','杜易簡','唐','御定全唐诗','yuding','','[]','有恥宿龍門，精彩先瞰渾。眼瘦呈近店，睡響徹遙林。',48,'御定全唐詩/json/869.json','["有恥宿龍門，精彩先瞰渾。眼瘦呈近店，睡響徹遙林。", "埒囊將舊識，制被異新婚。誰言驄馬使，翻作蟄熊蹲。"]'),
('yuding-19','始平諧詩','石抱忠','唐','御定全唐诗','yuding','','[]','平明發始平，薄暮至何城。庫塔朝雲上，晃池夜月明。',48,'御定全唐詩/json/869.json','["平明發始平，薄暮至何城。庫塔朝雲上，晃池夜月明。", "略彴橋頭逢長史，欞星門外揖司兵，一群縣尉驢騾驟，"]'),
('yuding-20','詠傅岩監祠','梁載言','唐','御定全唐诗','yuding','','[]','聞道監中溜，初言是大祠。很傍索傳馬，傯動出安徽。',48,'御定全唐詩/json/869.json','["聞道監中溜，初言是大祠。很傍索傳馬，傯動出安徽。", "衛司無帟幕，供膳乏鮮肥。形容消瘦盡，空往復空歸。"]'),
('yuding-21','嘲崔生','劉行敏','唐','御定全唐诗','yuding','','[]','崔生犯夜行，武候正嚴更。襆頭拳下落，高髻掌中擎。',48,'御定全唐詩/json/869.json','["崔生犯夜行，武候正嚴更。襆頭拳下落，高髻掌中擎。", "杖跡胸前出，繩文腕後生。愁人不惜夜，隨意曉參橫。"]'),
('yuding-22','又嘲楊文瓘','劉行敏','唐','御定全唐诗','yuding','','[]','武陵敬愛客，終宴不知疲。遣共渾王飲，錯宴延陀兒。',48,'御定全唐詩/json/869.json','["武陵敬愛客，終宴不知疲。遣共渾王飲，錯宴延陀兒。", "始被鴻臚識，終蒙禦史知。精神既如此，長歎複何為。"]'),
('yuding-23','嘲李叔慎、賀蘭僧伽、杜善賢','劉行敏','唐','御定全唐诗','yuding','','[]','叔慎騎烏馬，僧伽把漆弓。喚取長安令，共獵北山熊。',24,'御定全唐詩/json/869.json','["叔慎騎烏馬，僧伽把漆弓。喚取長安令，共獵北山熊。"]'),
('yuding-24','嘲父','陸子','唐','御定全唐诗','yuding','','[]','陸餘慶，筆頭無力觜頭硬。一朝受辭訟，十日判不竟。',24,'御定全唐詩/json/869.json','["陸餘慶，筆頭無力觜頭硬。一朝受辭訟，十日判不竟。"]'),
('yuding-25','回波詞','楊廷玉','唐','御定全唐诗','yuding','','[]','回波爾時廷玉，打獠取錢未足。',29,'御定全唐詩/json/869.json','["回波爾時廷玉，打獠取錢未足。", "阿姑婆見作天子，傍人不得棖觸。"]'),
('yuding-26','回波詞','中宗朝優人','唐','御定全唐诗','yuding','','[]','回波爾時栲栳，怕婦也是大好。',28,'御定全唐詩/json/869.json','["回波爾時栲栳，怕婦也是大好。", "外邊只有裴談，內裏無過李老。"]'),
('yuding-27','乞金魚詞','崔日用','唐','御定全唐诗','yuding','','[]','台中鼠子直須諳，信足跳樑上壁龕。倚翻燈脂汙張五，',24,'御定全唐詩/json/869.json','["台中鼠子直須諳，信足跳樑上壁龕。倚翻燈脂汙張五，"]'),
('yuding-28','又賜宴自歌','崔日用','唐','御定全唐诗','yuding','','[]','東館總是鵷鸞，南台自多杞梓。日用讀書萬卷，',21,'御定全唐詩/json/869.json','["東館總是鵷鸞，南台自多杞梓。日用讀書萬卷，"]'),
('yuding-29','詠癡','吳人','唐','御定全唐诗','yuding','','[]','榆兒複榆婦，造屋兼造車。十七八九夜，還書複借書。',24,'御定全唐詩/json/869.json','["榆兒複榆婦，造屋兼造車。十七八九夜，還書複借書。"]'),
('yuding-30','歇後','封抱一','唐','御定全唐诗','yuding','','[]','面作天地玄，鼻有雁門紫。既無左達承，何勞罔談彼。',24,'御定全唐詩/json/869.json','["面作天地玄，鼻有雁門紫。既無左達承，何勞罔談彼。"]'),
('yuding-31','送司功入京','麹崇裕','唐','御定全唐诗','yuding','','[]','崇裕有幸會，得遇明流行。司士向京去，曠野哭聲哀。',24,'御定全唐詩/json/869.json','["崇裕有幸會，得遇明流行。司士向京去，曠野哭聲哀。"]'),
('yuding-32','嶺南歸後獻詩','權龍褒','唐','御定全唐诗','yuding','','[]','龍褒有何罪，天恩放嶺南。敕知無罪過，追來與將軍。',24,'御定全唐詩/json/869.json','["龍褒有何罪，天恩放嶺南。敕知無罪過，追來與將軍。"]'),
('yuding-33','初到滄州呈州官','權龍褒','唐','御定全唐诗','yuding','','[]','遙看滄海城，楊柳鬱青青。中央一群漢，聚坐打杯觥。',24,'御定全唐詩/json/869.json','["遙看滄海城，楊柳鬱青青。中央一群漢，聚坐打杯觥。"]'),
('yuding-34','秋日述懷','權龍褒','唐','御定全唐诗','yuding','','[]','簷前飛七百，雪白後園強。飽食房裏側，家糞集野螂。',24,'御定全唐詩/json/869.json','["簷前飛七百，雪白後園強。飽食房裏側，家糞集野螂。"]'),
('yuding-35','喜雨','權龍褒','唐','御定全唐诗','yuding','','[]','暗去也沒雨，明來也沒雲。日頭赫赤出，地上綠氤氳。',24,'御定全唐詩/json/869.json','["暗去也沒雨，明來也沒雲。日頭赫赤出，地上綠氤氳。"]'),
('yuding-36','皇太子夏日賜宴詩','權龍褒','唐','御定全唐诗','yuding','','[]','嚴霜白浩浩，明月赤團團。',12,'御定全唐詩/json/869.json','["嚴霜白浩浩，明月赤團團。"]'),
('yuding-37','哭李嶠詩','崔泰之','唐','御定全唐诗','yuding','','[]','台閣神仙地，衣冠君子鄉。昨朝猶對坐，今日忽雲亡。',48,'御定全唐詩/json/869.json','["台閣神仙地，衣冠君子鄉。昨朝猶對坐，今日忽雲亡。", "魂隨司命鬼，魄逐見閻王。此時罷歡笑，無複向朝堂。"]'),
('yuding-38','詠尹字','蘇頲','唐','御定全唐诗','yuding','','[]','醜雖有足，甲不全身。見君無口，知伊少人。',20,'御定全唐詩/json/869.json','["醜雖有足，甲不全身。見君無口，知伊少人。"]'),
('yuding-39','詠王主敬','張敬忠','唐','御定全唐诗','yuding','','[]','有意嫌兵部，專心望考功。誰知腳踜蹬，卻落省牆東。',24,'御定全唐詩/json/869.json','["有意嫌兵部，專心望考功。誰知腳踜蹬，卻落省牆東。"]'),
('yuding-40','嘲邵景、蕭嵩','韋鏗','唐','御定全唐诗','yuding','','[]','一雙鬍子著緋袍，一個須多一鼻高。',32,'御定全唐詩/json/869.json','["一雙鬍子著緋袍，一個須多一鼻高。", "相對廳前捺且立，自慚身品世間毛。"]'),
('yuding-41','嘲韋鏗','邵景','唐','御定全唐诗','yuding','','[]','飄風忽起團團旋，倒地還如著腳z2。莫怪殿上空行事，卻為元非五品才。',33,'御定全唐詩/json/869.json','["飄風忽起團團旋，倒地還如著腳z2。莫怪殿上空行事，卻為元非五品才。"]'),
('yuding-42','詠毀天樞','李休烈','唐','御定全唐诗','yuding','','[]','天門街上倒天樞，火急先須卸火珠。',32,'御定全唐詩/json/869.json','["天門街上倒天樞，火急先須卸火珠。", "計合一條麻線挽，何勞兩縣索人夫。"]'),
('yuding-43','與李全交詩','石惠泰','唐','御定全唐诗','yuding','','[]','禦史非常任，參軍不久居。待君遷轉後，此職還到餘。',24,'御定全唐詩/json/869.json','["禦史非常任，參軍不久居。待君遷轉後，此職還到餘。"]'),
('yuding-44','嘲劉文樹','黃幡綽','唐','御定全唐诗','yuding','','[]','可憐好個劉文樹，髭須共頦頤別住。',34,'御定全唐詩/json/869.json','["可憐好個劉文樹，髭須共頦頤別住。", "文樹面孔不似猢猻，猢猻面孔強似文樹。"]'),
('yuding-45','尚書省門吟','祖詠','唐','御定全唐诗','yuding','','[]','落去他，兩兩三三戴帽子。',28,'御定全唐詩/json/869.json','["落去他，兩兩三三戴帽子。", "日暮祖侯吟一聲，長安竹柏皆枯死。"]'),
('yuding-46','上馬當山神','王昌齡','唐','御定全唐诗','yuding','','[]','青驄一匹昆侖牽，奏上大王不取錢。',32,'御定全唐詩/json/869.json','["青驄一匹昆侖牽，奏上大王不取錢。", "直為猛風波滾驟，莫怪昌齡不下船。"]'),
('yuding-47','竊李義府詩','張懷慶','唐','御定全唐诗','yuding','','[]','生情鏤月為歌扇，出性裁雲作舞衣。',32,'御定全唐詩/json/869.json','["生情鏤月為歌扇，出性裁雲作舞衣。", "照鏡自憐回雪影，來時好取洛川歸。"]'),
('yuding-48','答朝士','賀知章','唐','御定全唐诗','yuding','','[]','fk鏤銀盤盛蛤蜊，鏡湖蓴菜亂如絲。',33,'御定全唐詩/json/869.json','["fk鏤銀盤盛蛤蜊，鏡湖蓴菜亂如絲。", "鄉曲近來佳此味，遮渠不道是吳兒。"]'),
('yuding-49','和知章詩','顧況','唐','御定全唐诗','yuding','','[]','fk鏤銀盤盛炒蝦，鏡湖蓴菜亂如麻。',33,'御定全唐詩/json/869.json','["fk鏤銀盤盛炒蝦，鏡湖蓴菜亂如麻。", "漢兒女嫁吳兒婦，吳兒儘是漢兒爺。"]'),
('yuding-50','續茅山秀才吟','顧況','唐','御定全唐诗','yuding','','[]','駐馬上山阿，風來屎氣多。',12,'御定全唐詩/json/869.json','["駐馬上山阿，風來屎氣多。"]'),
('yuding-51','櫻桃子詩','史思明','唐','御定全唐诗','yuding','','[]','櫻桃子，半赤半已黃。一半與懷王，一半與周至。',22,'御定全唐詩/json/869.json','["櫻桃子，半赤半已黃。一半與懷王，一半與周至。"]'),
('yuding-0','譏元載詩','高亭','唐','御定全唐诗','yuding','','[]','上元官吏務剝削，江淮之人皆白著。',16,'御定全唐詩/json/870.json','["上元官吏務剝削，江淮之人皆白著。"]'),
('yuding-1','嘲趙謙光','賀遂涉','唐','御定全唐诗','yuding','','[]','員外由來美，郎中望亦優。寧知粉署裏，翻作土山頭。',24,'御定全唐詩/json/870.json','["員外由來美，郎中望亦優。寧知粉署裏，翻作土山頭。"]'),
('yuding-2','答賀遂涉','趙謙光','唐','御定全唐诗','yuding','','[]','錦帳隨情設，金爐任意熏。唯愁員外置，不應列星文。',24,'御定全唐詩/json/870.json','["錦帳隨情設，金爐任意熏。唯愁員外置，不應列星文。"]'),
('yuding-3','上浙東孟尚書','孔顒','唐','御定全唐诗','yuding','','[]','有個將軍不得名，唯教健卒喝書生。',32,'御定全唐詩/json/870.json','["有個將軍不得名，唯教健卒喝書生。", "尚書近日清如鏡，天子官街不許行。"]'),
('yuding-4','嘲柳州柳子厚','呂溫','唐','御定全唐诗','yuding','','[]','柳州柳刺史，種柳柳江邊。柳管依然在，千秋柳拂天。',24,'御定全唐詩/json/870.json','["柳州柳刺史，種柳柳江邊。柳管依然在，千秋柳拂天。"]'),
('yuding-5','嘲黔南觀察南卓','呂溫','唐','御定全唐诗','yuding','','[]','終南南太守，南郡在雲南。閑向南亭醉，南風變俗談。',24,'御定全唐詩/json/870.json','["終南南太守，南郡在雲南。閑向南亭醉，南風變俗談。"]'),
('yuding-6','戲簡朱壇詩','張祜','唐','御定全唐诗','yuding','','[]','昔人有玉碗，擊之千里鳴。今日睹斯文，碗有當時聲。',24,'御定全唐詩/json/870.json','["昔人有玉碗，擊之千里鳴。今日睹斯文，碗有當時聲。"]'),
('yuding-7','戲顏郎官騎獵詩','張祜','唐','御定全唐诗','yuding','','[]','忽聞射獵出軍城，人著戎衣馬帶纓。',32,'御定全唐詩/json/870.json','["忽聞射獵出軍城，人著戎衣馬帶纓。", "倒把角弓呈一箭，滿山狐兔當頭行。"]'),
('yuding-8','嘲張祜','朱沖和','唐','御定全唐诗','yuding','','[]','白在東都元已薨，蘭台鳳閣少人登。',32,'御定全唐詩/json/870.json','["白在東都元已薨，蘭台鳳閣少人登。", "冬瓜堰下逢張祜，牛屎堆邊說我能。"]'),
('yuding-9','嘲妓','崔涯','唐','御定全唐诗','yuding','','[]','雖得蘇方木，猶貪玳瑁皮。懷胎十個月，生下昆侖兒。',56,'御定全唐詩/json/870.json','["雖得蘇方木，猶貪玳瑁皮。懷胎十個月，生下昆侖兒。", "布袍披襖火燒氈，紙補箜篌麻接弦。", "更著一雙皮屐子，紇梯紇榻出門前。"]'),
('yuding-10','嘲李端端','崔涯','唐','御定全唐诗','yuding','','[]','黃昏不語不知行，鼻似煙窗耳似鐺。',64,'御定全唐詩/json/870.json','["黃昏不語不知行，鼻似煙窗耳似鐺。", "獨把象牙梳插鬢，昆侖山上月初明。", "覓得黃騮鞁繡鞍，善和坊裏取端端。", "揚州近日渾成差，一朵能行白牡丹。"]'),
('yuding-11','詠崔雲娘','李宣古','唐','御定全唐诗','yuding','','[]','何事最堪悲，雲娘只首奇。瘦拳拋令急，長嘯出歌遲。',48,'御定全唐詩/json/870.json','["何事最堪悲，雲娘只首奇。瘦拳拋令急，長嘯出歌遲。", "只見肩侵鬢，唯憂骨透皮。不須當戶立，頭上有鍾馗。"]'),
('yuding-12','嘲妓','杜牧','唐','御定全唐诗','yuding','','[]','盤古當時有遠孫，尚令今日逞家門。一車白土將泥項，',40,'御定全唐詩/json/870.json','["盤古當時有遠孫，尚令今日逞家門。一車白土將泥項，", "不須惆悵憂難嫁，待與將書問樂坤。"]'),
('yuding-13','嘲遊使君','盧肇','唐','御定全唐诗','yuding','','[]','白帝城頭二月時，忍教清醒看花枝。',32,'御定全唐詩/json/870.json','["白帝城頭二月時，忍教清醒看花枝。", "莫言世上無袁許，客子由來是相師。"]'),
('yuding-14','嘲李瑒題名','韋蟾','唐','御定全唐诗','yuding','','[]','渭水秦山照眼明，希仁何事寡詩情。',32,'御定全唐詩/json/870.json','["渭水秦山照眼明，希仁何事寡詩情。", "只因學得虞姬婿，書字才能記姓名。"]'),
('yuding-15','聞鹿鳴互謔','嚴震','唐','御定全唐诗','yuding','','[]','釜戴山中鹿又鳴，——中表',44,'御定全唐詩/json/870.json','["釜戴山中鹿又鳴，——中表", "此際多應到表兄。——嚴震", "表兄不是嚴家子，合是三兄與四兄。——中表"]'),
('yuding-16','及第後寄李紳','章孝標','唐','御定全唐诗','yuding','','[]','及第全勝十政官，金鞍鍍了出長安。',32,'御定全唐詩/json/870.json','["及第全勝十政官，金鞍鍍了出長安。", "馬頭漸入揚州郭，為報時人洗眼看。"]'),
('yuding-17','答章孝標','李紳','唐','御定全唐诗','yuding','','[]','假金只用真金鍍，若是真金不鍍金。',32,'御定全唐詩/json/870.json','["假金只用真金鍍，若是真金不鍍金。", "十載長安得一第，何須空腹用高心。"]'),
('yuding-18','戲柳棠','楊汝士','唐','御定全唐诗','yuding','','[]','文章漫道能吞鳳，杯酒何曾解吃魚。',32,'御定全唐詩/json/870.json','["文章漫道能吞鳳，杯酒何曾解吃魚。", "今日梓州張社會，應須遭這老尚書。"]'),
('yuding-19','答楊尚書','柳棠','唐','御定全唐诗','yuding','','[]','未向燕台逢厚禮，幸因社會接餘歡。',32,'御定全唐詩/json/870.json','["未向燕台逢厚禮，幸因社會接餘歡。", "一魚吃了終無愧，鯤化為鵬也不難。"]'),
('yuding-20','又忤楊尚書詩','柳棠','唐','御定全唐诗','yuding','','[]','莫言名位未相儔，風月何曾阻獻酬。',32,'御定全唐詩/json/870.json','["莫言名位未相儔，風月何曾阻獻酬。", "前輩不須輕後輩，靖安今日在衡州。"]'),
('yuding-21','嘲郭凝素','朱澤','唐','御定全唐诗','yuding','','[]','三春桃李本無言，苦被殘陽鳥雀喧。',32,'御定全唐詩/json/870.json','["三春桃李本無言，苦被殘陽鳥雀喧。", "借問東鄰效西子，何如郭素擬王軒。"]'),
('yuding-22','紀中表試案','鄭光業','唐','御定全唐诗','yuding','','[]','新糊案子，其白如銀。入試出試，千春萬春。',20,'御定全唐詩/json/870.json','["新糊案子，其白如銀。入試出試，千春萬春。"]'),
('yuding-23','醉題廣州使院','鄭愚','唐','御定全唐诗','yuding','','[]','數年百姓受饑荒，太守貪殘似虎狼。',32,'御定全唐詩/json/870.json','["數年百姓受饑荒，太守貪殘似虎狼。", "今日海隅魚米賤，大須慚愧石榴黃。"]'),
('yuding-24','擬權龍褒體贈鄠縣李令及寄朝右','鄭愚','唐','御定全唐诗','yuding','','[]','鄠縣李長官，橫琴膝上弄。不聞有政聲，但見手子動。',24,'御定全唐詩/json/870.json','["鄠縣李長官，橫琴膝上弄。不聞有政聲，但見手子動。"]'),
('yuding-25','題滄浪峽榜','鄭仁表','唐','御定全唐诗','yuding','','[]','分峽東西路正長，行人名利火然湯。',32,'御定全唐詩/json/870.json','["分峽東西路正長，行人名利火然湯。", "路傍著板滄浪峽，真是將閑攪撩忙。"]'),
('yuding-26','戲妻族語不正','胡曾','唐','御定全唐诗','yuding','','[]','呼十卻為石，喚針將作真。忽然雲雨至，總道是天因。',24,'御定全唐詩/json/870.json','["呼十卻為石，喚針將作真。忽然雲雨至，總道是天因。"]'),
('yuding-27','婢僕詩','李昌符','唐','御定全唐诗','yuding','','[]','春娘愛上酒家樓，不怕歸遲總不憂。',64,'御定全唐詩/json/870.json','["春娘愛上酒家樓，不怕歸遲總不憂。", "推道那家娘子臥，且留教住待梳頭。", "不論秋菊與春花，個個能噇空腹茶。", "無事莫教頻入庫，一名閑物要些些。"]'),
('yuding-28','嘲鄭傪妓','孫子多','唐','御定全唐诗','yuding','','[]','相公經文複經武，常侍好今兼好古。',32,'御定全唐詩/json/870.json','["相公經文複經武，常侍好今兼好古。", "昔人曾聞阿武婆，今日親見阿婆舞。"]'),
('yuding-29','嘲趙璘','薛能','唐','御定全唐诗','yuding','','[]','巡關每傍摴蒲局，望月還登乞巧樓。',64,'御定全唐詩/json/870.json','["巡關每傍摴蒲局，望月還登乞巧樓。", "第一莫教嬌太過，緣人衣帶上人頭。", "不知原在鞍轎裏，將謂空馱席帽歸。", "火爐床上平身立，便與夫人作鏡臺。"]'),
('yuding-30','口號','薛能','唐','御定全唐诗','yuding','','[]','素脊鳴秋杖，烏靴響暮廳。——薛能',33,'御定全唐詩/json/870.json','["素脊鳴秋杖，烏靴響暮廳。——薛能", "刃飛三尺雪，白日落文星。——秦宗權"]'),
('yuding-31','嘲歸仁紹龜詩','皮日休','唐','御定全唐诗','yuding','','[]','硬骨殘形知幾秋，屍骸終是不風流。',32,'御定全唐詩/json/870.json','["硬骨殘形知幾秋，屍骸終是不風流。", "頑皮死後鑽須遍，都為平生不出頭。"]'),
('yuding-32','詠螃蟹呈浙西從事','皮日休','唐','御定全唐诗','yuding','','[]','未游滄海早知名，有骨還從肉上生。',32,'御定全唐詩/json/870.json','["未游滄海早知名，有骨還從肉上生。", "莫道無心畏雷電，海龍王處也橫行。"]'),
('yuding-33','題中書壁','鄭綮','唐','御定全唐诗','yuding','','[]','側坡蛆蜫蜦，蟻子競來拖。一朝白雨中，無鈍無嘍羅。',24,'御定全唐詩/json/870.json','["側坡蛆蜫蜦，蟻子競來拖。一朝白雨中，無鈍無嘍羅。"]'),
('yuding-34','別廬州郡人','鄭綮','唐','御定全唐诗','yuding','','[]','唯有兩行公廨淚，一時灑向渡頭風。',16,'御定全唐詩/json/870.json','["唯有兩行公廨淚，一時灑向渡頭風。"]'),
('yuding-35','戲答成汭','徐彥若','唐','御定全唐诗','yuding','','[]','南海黃茅瘴，不死成和尚。',12,'御定全唐詩/json/870.json','["南海黃茅瘴，不死成和尚。"]'),
('yuding-36','醉中謔浙江廉使','崔立言','唐','御定全唐诗','yuding','','[]','山夫留意向丹梯，連帥邀來出藥畦。',32,'御定全唐詩/json/870.json','["山夫留意向丹梯，連帥邀來出藥畦。", "常見浙東誇鏡水，鏡湖元在浙江西。"]'),
('yuding-37','戲題盱眙邵明府壁','韋鵬翼','唐','御定全唐诗','yuding','','[]','豈肯閑尋竹徑行，卻嫌絲管好蛙聲。',32,'御定全唐詩/json/870.json','["豈肯閑尋竹徑行，卻嫌絲管好蛙聲。", "自從煮鶴燒琴後，背卻青山臥月明。"]'),
('yuding-38','題大樑臨汴驛','姚嶸','唐','御定全唐诗','yuding','','[]','近日侯門不重才，莫將文藝擬為媒。',32,'御定全唐詩/json/870.json','["近日侯門不重才，莫將文藝擬為媒。", "相逢若要如膠漆，不是紅妝即撥灰。"]'),
('yuding-39','題仙娥驛','李日新','唐','御定全唐诗','yuding','','[]','商山食店大悠悠，陳鶡z2鑼古ie頭。',34,'御定全唐詩/json/870.json','["商山食店大悠悠，陳鶡z2鑼古ie頭。", "更有台中牛肉炙，尚盤數臠紫光球。"]'),
('yuding-40','嘲染家','柳逢','唐','御定全唐诗','yuding','','[]','紫綠終朝染，因何不識非。莆田竹木貴，背負十柴歸。',24,'御定全唐詩/json/870.json','["紫綠終朝染，因何不識非。莆田竹木貴，背負十柴歸。"]'),
('yuding-41','贈漳州崔使君鄉飲翻韻詩','黎瓘','唐','御定全唐诗','yuding','','[]','慣向溪邊折柳楊，因循行客到州漳。',32,'御定全唐詩/json/870.json','["慣向溪邊折柳楊，因循行客到州漳。", "無端觸忤王衙押，不得今朝看飲鄉。"]'),
('yuding-42','示妓榜子','張保胤','唐','御定全唐诗','yuding','','[]','綠羅裙下標三棒，紅粉腮邊淚兩行。',32,'御定全唐詩/json/870.json','["綠羅裙下標三棒，紅粉腮邊淚兩行。", "叉手向前咨大使，這回不敢惱兒郎。"]'),
('yuding-43','又留別同院','張保胤','唐','御定全唐诗','yuding','','[]','憶昔當年富貴時，如今頭腦尚依稀。布袍破後思宮內，',40,'御定全唐詩/json/870.json','["憶昔當年富貴時，如今頭腦尚依稀。布袍破後思宮內，", "如今憔悴離南海，恰似當時幸蜀時。"]'),
('yuding-44','桂州筵上贈胡予女','陸岩夢','唐','御定全唐诗','yuding','','[]','自道風流不可攀，卻堪蹙額更頹顏。眼睛深卻湘江水，',40,'御定全唐詩/json/870.json','["自道風流不可攀，卻堪蹙額更頹顏。眼睛深卻湘江水，", "孟陽死後欲千載，猶在佳人覓往還。"]'),
('yuding-45','戲答朝士','李都','唐','御定全唐诗','yuding','','[]','華緘千里到荊門，章草縱橫任意論。應笑鐘張虛用力，',40,'御定全唐詩/json/870.json','["華緘千里到荊門，章草縱橫任意論。應笑鐘張虛用力，", "深荷故人相厚處，天行時氣許教吞。"]'),
('yuding-46','嘲僧惟恭','荊人','唐','御定全唐诗','yuding','','[]','靈巋作盡業，惟恭繼其跡。地獄千萬重，莫厭排頭入。',24,'御定全唐詩/json/870.json','["靈巋作盡業，惟恭繼其跡。地獄千萬重，莫厭排頭入。"]'),
('yuding-47','題酒戶修孔廟狀','馮道幕客','唐','御定全唐诗','yuding','','[]','槐影參差覆杏壇，儒門子弟盡高官。',32,'御定全唐詩/json/870.json','["槐影參差覆杏壇，儒門子弟盡高官。", "卻教酒戶重修廟，覓我慚惶也不難。"]'),
('yuding-48','孔廟口號','李花開','唐','御定全唐诗','yuding','','[]','破落三間屋，蕭條一旅人。不知負何事，生死厄于陳。',24,'御定全唐詩/json/870.json','["破落三間屋，蕭條一旅人。不知負何事，生死厄于陳。"]'),
('yuding-49','答妻','馮暉','唐','御定全唐诗','yuding','','[]','休說辦不辦，且看甕裏飛出雁。',14,'御定全唐詩/json/870.json','["休說辦不辦，且看甕裏飛出雁。"]'),
('yuding-50','題僧院','李濤','唐','御定全唐诗','yuding','','[]','走卻坐禪客，移將不動尊。世間顛倒事，八萬四千門。',24,'御定全唐詩/json/870.json','["走卻坐禪客，移將不動尊。世間顛倒事，八萬四千門。"]'),
('yuding-51','詠垂絲蜘蛛嘲雲辨僧','楊苧蘿','唐','御定全唐诗','yuding','','[]','吃得肚嬰撐，尋思繞寺行。空中設羅網，只待殺眾生。',24,'御定全唐詩/json/870.json','["吃得肚嬰撐，尋思繞寺行。空中設羅網，只待殺眾生。"]'),
('yuding-52','自嘲絕句','馮涓','唐','御定全唐诗','yuding','','[]','取水郎中何日了，破柴員外幾時休。',32,'御定全唐詩/json/870.json','["取水郎中何日了，破柴員外幾時休。", "早知蜀地區娵與，悔不長安大比丘。"]'),
('yuding-53','哭亡將詩','盧延讓','唐','御定全唐诗','yuding','','[]','自是硇砂發，非幹駭石傷。牒高身上職，碗大背邊創。',24,'御定全唐詩/json/870.json','["自是硇砂發，非幹駭石傷。牒高身上職，碗大背邊創。"]'),
('yuding-54','詠王給事','蔣貽恭','唐','御定全唐诗','yuding','','[]','厥父元非道郡奴，允光何事太侏儒。',32,'御定全唐詩/json/870.json','["厥父元非道郡奴，允光何事太侏儒。", "可中與個皮褌著，擎得天王左腳無。"]'),
('yuding-55','詠金剛','蔣貽恭','唐','御定全唐诗','yuding','','[]','揚眉鬥目惡精神，捏合將來恰似真。',32,'御定全唐詩/json/870.json','["揚眉鬥目惡精神，捏合將來恰似真。", "剛被時流借拳勢，不知身自是泥人。"]'),
('yuding-56','詠傴背子','蔣貽恭','唐','御定全唐诗','yuding','','[]','出得門來背拄天，同行難可與差肩。',32,'御定全唐詩/json/870.json','["出得門來背拄天，同行難可與差肩。", "若教倚向閑窗下，恰似箜篌不著弦。"]'),
('yuding-57','詠安仁宰搗蒜','蔣貽恭','唐','御定全唐诗','yuding','','[]','安仁縣令好誅求，百姓脂膏滿面流。半破磁缸成醋酒，',40,'御定全唐詩/json/870.json','["安仁縣令好誅求，百姓脂膏滿面流。半破磁缸成醋酒，", "半醉半醒齊出縣，共傷塗炭不勝愁。"]'),
('yuding-58','五門街望有題','蔣貽恭','唐','御定全唐诗','yuding','','[]','我皇開國十餘年，一輩超升炙手歡。',32,'御定全唐詩/json/870.json','["我皇開國十餘年，一輩超升炙手歡。", "閑向五門樓下望，衙官騎馬使衙官。"]'),
('yuding-59','謝郎中惠茶','蔣貽恭','唐','御定全唐诗','yuding','','[]','三斤綠茗賜貽恭，一種頒沾事不同。',32,'御定全唐詩/json/870.json','["三斤綠茗賜貽恭，一種頒沾事不同。", "想料腸懷無答處，披毛戴角謝郎中。"]'),
('yuding-60','詠蝦蟆','蔣貽恭','唐','御定全唐诗','yuding','','[]','坐臥兼行總一般，向人努眼太無端。',32,'御定全唐詩/json/870.json','["坐臥兼行總一般，向人努眼太無端。", "欲知自己形骸小，試就蹄涔照影看。"]'),
('yuding-61','住名山日陳情上府主高太保','蔣貽恭','唐','御定全唐诗','yuding','','[]','名山主簿實堪愁，難咬他家大骨頭。',32,'御定全唐詩/json/870.json','["名山主簿實堪愁，難咬他家大骨頭。", "米納功南錢納府，只看江面水東流。"]'),
('yuding-62','詠刺蝟','李貞白','唐','御定全唐诗','yuding','','[]','行似針氈動，臥若栗球圓。莫欺如此大，誰敢便行拳。',24,'御定全唐詩/json/870.json','["行似針氈動，臥若栗球圓。莫欺如此大，誰敢便行拳。"]'),
('yuding-63','謁貴公子，不禮，書格子屏風','李貞白','唐','御定全唐诗','yuding','','[]','道格何曾格，言糊又不糊。渾身總是眼，還解識人無。',24,'御定全唐詩/json/870.json','["道格何曾格，言糊又不糊。渾身總是眼，還解識人無。"]'),
('yuding-64','詠月','李貞白','唐','御定全唐诗','yuding','','[]','當塗當塗見，蕪湖蕪湖見。八月十五夜，一似沒柄扇。',24,'御定全唐詩/json/870.json','["當塗當塗見，蕪湖蕪湖見。八月十五夜，一似沒柄扇。"]'),
('yuding-65','詠狗蚤','李貞白','唐','御定全唐诗','yuding','','[]','與虱都來不較多，zh挑筋斗太嘍羅。',33,'御定全唐詩/json/870.json','["與虱都來不較多，zh挑筋斗太嘍羅。", "忽然管著一籃子，有甚心情那你何。"]'),
('yuding-66','詠罌粟子','李貞白','唐','御定全唐诗','yuding','','[]','倒排雙陸子，希插碧牙籌。既似犧牛乳，又如鈴馬兜。',36,'御定全唐詩/json/870.json','["倒排雙陸子，希插碧牙籌。既似犧牛乳，又如鈴馬兜。", "鼓捶並瀑箭，直是有來由。"]'),
('yuding-67','詠蟹','李貞白','唐','御定全唐诗','yuding','','[]','蟬眼龜形腳似蛛，未曾正面向人趨。',32,'御定全唐詩/json/870.json','["蟬眼龜形腳似蛛，未曾正面向人趨。", "如今飣在盤筵上，得似江湖亂走無。"]'),
('yuding-68','示女詩','郫城令','唐','御定全唐诗','yuding','','[]','深宮富貴事風流，莫忘生身老骨頭。',32,'御定全唐詩/json/870.json','["深宮富貴事風流，莫忘生身老骨頭。", "因與太師歡笑處，為吾方便覓彭州。"]'),
('yuding-69','寄女','李令','唐','御定全唐诗','yuding','','[]','有人教我向衡陽，一度思歸欲斷腸。',32,'御定全唐詩/json/870.json','["有人教我向衡陽，一度思歸欲斷腸。", "為報豔妻兼少女，與吾覓取朗州場。"]'),
('yuding-70','諷劉炎索賄詩','太守','唐','御定全唐诗','yuding','','[]','未到桃源時，長憶出家景。及到桃源了，還似鑒中影。',24,'御定全唐詩/json/870.json','["未到桃源時，長憶出家景。及到桃源了，還似鑒中影。"]'),
('yuding-71','被按自悔詩','劉炎','唐','御定全唐诗','yuding','','[]','早知太守如狼虎，獵取膏粱以啖之。',16,'御定全唐詩/json/870.json','["早知太守如狼虎，獵取膏粱以啖之。"]'),
('yuding-0','與王仙客互嘲','甘洽','唐','御定全唐诗','yuding','','[]','王，計爾應姓田。為你面撥獺，抽卻你兩邊。——甘洽',48,'御定全唐詩/json/871.json','["王，計爾應姓田。為你面撥獺，抽卻你兩邊。——甘洽", "甘，計爾應姓丹。為你頭不曲，回腳向上安。——仙客"]'),
('yuding-1','題濠州高塘館','閻敬愛','唐','御定全唐诗','yuding','','[]','借問襄王安在哉，山川此地勝陽臺。',32,'御定全唐詩/json/871.json','["借問襄王安在哉，山川此地勝陽臺。", "今宵寓宿高塘館，神女何曾入夢來。"]'),
('yuding-2','題敬愛詩後','李和風','唐','御定全唐诗','yuding','','[]','高唐不是這高塘，淮畔荊南各異方。',32,'御定全唐詩/json/871.json','["高唐不是這高塘，淮畔荊南各異方。", "若向此中求薦枕，參差笑殺楚襄王。"]'),
