('yuding-5','馬重績占隨卦繇辭','不詳','唐','御定全唐诗','yuding','','[]','南瞻析木，木不自續。虛而動之，動隨其覆。',20,'御定全唐詩/json/880.json','["南瞻析木，木不自續。虛而動之，動隨其覆。"]'),
('yuding-6','方龜精為錢元懿蔔詞','不詳','唐','御定全唐诗','yuding','','[]','太乙接天河，金華寶貝多。郡侯六十六，別處不經過。',24,'御定全唐詩/json/880.json','["太乙接天河，金華寶貝多。郡侯六十六，別處不經過。"]'),
('yuding-7','葉簡占失牛','不詳','唐','御定全唐诗','yuding','','[]','占失牛，已被家邊載上州。欲知賊姓一斤求，',20,'御定全唐詩/json/880.json','["占失牛，已被家邊載上州。欲知賊姓一斤求，"]'),
('yuding-8','又射覆橘子','不詳','唐','御定全唐诗','yuding','','[]','圓似珠，色如丹。儻能擘破同分吃，爭不慚愧洞庭山。',24,'御定全唐詩/json/880.json','["圓似珠，色如丹。儻能擘破同分吃，爭不慚愧洞庭山。"]'),
('yuding-9','射覆巾子','不詳','唐','御定全唐诗','yuding','','[]','近來好裹束，各自競尖新。秤無三五兩，因何號一斤。',24,'御定全唐詩/json/880.json','["近來好裹束，各自競尖新。秤無三五兩，因何號一斤。"]'),
('yuding-10','射覆二雞子','不詳','唐','御定全唐诗','yuding','','[]','此物不難知，一雄兼一雌。誰將打破看，方明混沌時。',24,'御定全唐詩/json/880.json','["此物不難知，一雄兼一雌。誰將打破看，方明混沌時。"]'),
('yuding-11','天沖星占','不詳','唐','御定全唐诗','yuding','','[]','天沖抱極泣帝前，血濁霧下天下冤。',16,'御定全唐詩/json/880.json','["天沖抱極泣帝前，血濁霧下天下冤。"]'),
('yuding-12','占月語','不詳','唐','御定全唐诗','yuding','','[]','月如彎弓，少雨多風。月如仰瓦，不求自下。',20,'御定全唐詩/json/880.json','["月如彎弓，少雨多風。月如仰瓦，不求自下。"]'),
('yuding-13','占雨','不詳','唐','御定全唐诗','yuding','','[]','幹星照濕土，明日依舊雨。',40,'御定全唐詩/json/880.json','["幹星照濕土，明日依舊雨。", "雲行西，星照泥。", "朝霞不出門，暮霞行千里。", "天將雨，鳩逐婦。"]'),
('yuding-14','占四時甲子雨','不詳','唐','御定全唐诗','yuding','','[]','春雨甲子，赤地千里。夏雨甲子，乘船入市。秋雨甲子，',25,'御定全唐詩/json/880.json','["春雨甲子，赤地千里。夏雨甲子，乘船入市。秋雨甲子，"]'),
('yuding-15','占年','不詳','唐','御定全唐诗','yuding','','[]','要見麥，見三白。',19,'御定全唐詩/json/880.json','["要見麥，見三白。", "正月三白，田公笑赫赫。"]'),
('yuding-16','樹稼諺','不詳','唐','御定全唐诗','yuding','','[]','樹稼，達官怕。',7,'御定全唐詩/json/880.json','["樹稼，達官怕。"]'),
('yuding-17','相書語','不詳','唐','御定全唐诗','yuding','','[]','目有四白，五夫守宅。',10,'御定全唐詩/json/880.json','["目有四白，五夫守宅。"]'),
('yuding-18','葬書語','不詳','唐','御定全唐诗','yuding','','[]','葬壓龍角，其棺必斫。',62,'御定全唐詩/json/880.json','["葬壓龍角，其棺必斫。", "朱雀和鳴，子孫盛榮。", "朱雀悲哀，棺中見灰。", "安龍頭，枕龍角。不三年，自消鑠。", "安龍頭，枕龍耳。不三年，萬乘至。"]'),
('yuding-19','陰陽書語','不詳','唐','御定全唐诗','yuding','','[]','喬木先枯，眾子必孤。',10,'御定全唐詩/json/880.json','["喬木先枯，眾子必孤。"]'),
('yuding-20','本草采萍時日歌','不詳','唐','御定全唐诗','yuding','','[]','不在山，不在岸，采我之時七月半。選甚癱風與緩風，',24,'御定全唐詩/json/880.json','["不在山，不在岸，采我之時七月半。選甚癱風與緩風，"]'),
('yuding-21','和劑方補骨脂丸方詩','不詳','唐','御定全唐诗','yuding','','[]','三年時節向邊隅，人信方知藥力殊。',32,'御定全唐詩/json/880.json','["三年時節向邊隅，人信方知藥力殊。", "奪得春光來在手，青娥休笑白髭須。"]'),
('yuding-22','李廷珪藏墨訣','不詳','唐','御定全唐诗','yuding','','[]','贈爾烏玉玦，泉清研須潔。避暑懸葛囊，臨風度梅月。',24,'御定全唐詩/json/880.json','["贈爾烏玉玦，泉清研須潔。避暑懸葛囊，臨風度梅月。"]'),
('yuding-0','蒙求','李瀚2','唐','御定全唐诗','yuding','','[]','王戎簡要，裴楷清通。孔明臥龍，呂望非熊。楊震關西，',600,'御定全唐詩/json/881.json','["王戎簡要，裴楷清通。孔明臥龍，呂望非熊。楊震關西，", "郅都蒼鷹，甯成乳虎。周嵩狼抗，梁冀跋扈。郗超髯參，", "武仲不休，士衡患多。桓譚非讖，王商止訛。嵇呂命駕，", "黃霸政殊，梁習治最。墨子悲絲，楊朱泣岐。朱博烏集，", "燕昭築台，鄭莊置驛。瓘靖二妙，岳湛連璧。郤詵一枝，", "晉宣狼顧，漢祖龍顏。鮑靚記井，羊祜識環。仲容青雲，", "蕭何定律，叔孫制禮。葛豐刺舉，息躬曆詆。管甯割席，", "孫楚漱石，郝隆曬書。枚皋詣闕，充國自贊。王衍風鑒，", "山濤識量，毛玠公方。袁盎卻座，衛瓘撫床。于公高門，", "詰汾興魏，鱉靈王蜀。不疑誣金，卞和泣玉。檀卿沐猴，", "王忳繡被，張氏銅鉤。丁公遽戮，雍齒先侯。陳雷膠漆，", "郭文游山，袁宏泊渚。黃琬對日，秦宓論天。孟軻養素，", "魯恭馴雉，宋均去獸。廣客蛇影，殷師牛鬥。元禮模楷，", "枚乘蒲輪，鄭均白衣。陵母伏劍，軻親斷機。齊後破環，", "羅含吞鳥，江淹夢筆。李廞清貞，劉驎高率。蔣詡三徑，", "西施捧心，孫壽折腰。靈輒扶輪，魏顆結草。逸少傾寫，", "公超霧市，魯般雲梯。田單火牛，江逌爇雞。蔡裔殞盜，", "淵客泣珠，交甫解佩。龔勝不屈，孫寶自劾。呂安題鳳，", "馮衍歸裏，張昭塞門。蘇韶鬼靈，盧充幽婚。震畏四知，", "三王尹京，二鮑糾慝。孫康映雪，車胤聚螢。李充四部，", "阮宣杖頭，畢卓甕下。文伯羞鱉，孟宗寄鮓。史丹青蒲，", "華歆忤旨，陳群蹙容。王浚懸刀，丁固生松。姜維膽鬥，", "杜康造酒，蒼頡制字。樗裏智囊，邊韶經笥。滕公佳城，", "顏叔秉燭，宋弘不諧。鄧通銅山，郭況金穴。秦彭樊轅，"]'),
('yuding-0','宗廟九德之歌辭','褚亮','唐','御定全唐诗','yuding','','[]','皇祖誕慶，于昭於天。積德斯遠，茂攸緒先。',80,'御定全唐詩/json/882.json','["皇祖誕慶，于昭於天。積德斯遠，茂攸緒先。", "維文應曆，神武弘宣。肇跡□水，成功阪泉。", "道光覆載，聲穆吉先。式備犧象，用□牲牷。", "禮終九獻，樂展四懸。神貺景福，遐哉永年。"]'),
('yuding-1','太廟祼地歌辭','陳叔達','唐','御定全唐诗','yuding','','[]','清廟既祼，鬱鬯推禮。大哉孝思，嚴恭祖禰。',60,'御定全唐詩/json/882.json','["清廟既祼，鬱鬯推禮。大哉孝思，嚴恭祖禰。", "龍袞以祭，鸞刀思啟。發德朱弦，升歌丹陛。", "遙享粢盛，堂斟況齊。降福穰穰，來儀濟濟。"]'),
('yuding-2','階前石竹','王績','唐','御定全唐诗','yuding','','[]','上天布甘雨，萬物咸均平。自顧微且賤，亦得蒙滋榮。',84,'御定全唐詩/json/882.json','["上天布甘雨，萬物咸均平。自顧微且賤，亦得蒙滋榮。", "萋萋結綠枝，曄曄垂朱英。常恐零露降，不得全其生。", "歎息聊自思，此生豈我情。昔我未生時，誰者令我萌。", "棄置勿重陳，委化何所營。"]'),
('yuding-3','九月九日','崔善為','唐','御定全唐诗','yuding','','[]','九日重陽節，三秋季月殘。菊花催晚氣，萸房辟早寒。',48,'御定全唐詩/json/882.json','["九日重陽節，三秋季月殘。菊花催晚氣，萸房辟早寒。", "霜濃鷹擊遠，霧重雁飛難。誰憶龍山外，蕭條邊興闌。"]'),
('yuding-4','奉和九月九日應制','許敬宗','唐','御定全唐诗','yuding','','[]','爽氣申時豫，臨秋肆武功。太液榮光發，曾城佳氣融。',109,'御定全唐詩/json/882.json','["爽氣申時豫，臨秋肆武功。太液榮光發，曾城佳氣融。", "紫霄寒暑麗，黃山極望通。講藝遵先fN，睹德暢宸衷。", "鷲嶺飛夏服，娥魄亂雕弓。汗浹鑣流赭，塵生埒散紅。", "飲羽驚開石，中葉遽凋叢。雁殫雲路靜，烏墜日輪空。", "九流參廣宴，萬宇抃恩隆。"]'),
('yuding-5','奉和守歲應制','許敬宗','唐','御定全唐诗','yuding','','[]','玉管移玄序，金奏賞彤闈。祥鸞歌裏轉，春燕舞前歸。',60,'御定全唐詩/json/882.json','["玉管移玄序，金奏賞彤闈。祥鸞歌裏轉，春燕舞前歸。", "壽爵傳三禮，燈枝麗九微。運廣熏風積，恩深湛露晞。", "送寒終此夜，延宴待晨暉。"]'),
('yuding-6','淩晨','盧照鄰','唐','御定全唐诗','yuding','','[]','日掩鴻都夕，河低亂箭移。蟲飛明月戶，鵲繞落花枝。',48,'御定全唐詩/json/882.json','["日掩鴻都夕，河低亂箭移。蟲飛明月戶，鵲繞落花枝。", "蘭襟帳北壑，玉匣鼓文漪。聞有啼鶯處，暗幄曉雲披。"]'),
('yuding-7','登北固山','宋之問','唐','御定全唐诗','yuding','','[]','京鎮周天險，東南作北關。埭橫江曲路，戍入海中山。',48,'御定全唐詩/json/882.json','["京鎮周天險，東南作北關。埭橫江曲路，戍入海中山。", "望越心初切，思秦鬢已斑。空憐上林雁，朝夕待春還。"]'),
('yuding-8','陪群公登箕山賦得群字','宋之問','唐','御定全唐诗','yuding','','[]','許由去已遠，冥莫見幽墳。世薄人不貴，茲山唯白雲。',60,'御定全唐詩/json/882.json','["許由去已遠，冥莫見幽墳。世薄人不貴，茲山唯白雲。", "甯知三千歲，複有堯為君。時佐激頹俗，登箕挹清芬。", "高節雖旦暮，邈與洪崖群。"]'),
('yuding-9','人日兼立春小園宴','蘇頲','唐','御定全唐诗','yuding','','[]','黃山積高次，表裏望京邑。白日最靈朝，登攀盡原隰。',72,'御定全唐詩/json/882.json','["黃山積高次，表裏望京邑。白日最靈朝，登攀盡原隰。", "年灰律象動，陽氣開迎入。煙靄長薄含，臨流小溪澀。", "賓朋莫我棄，詞賦當春立。更與韶物期，不孤東園集。"]'),
('yuding-10','和黃門舅十五夜作','蘇頲','唐','御定全唐诗','yuding','','[]','聞君陌上來，歌管沸相催。孤月連明照，千燈合暗開。',48,'御定全唐詩/json/882.json','["聞君陌上來，歌管沸相催。孤月連明照，千燈合暗開。", "寶裝遊騎出，香繞看車回。獨有歸閑意，春庭伴落梅。"]'),
('yuding-11','登綿州富樂山別李道士策','薛曜','唐','御定全唐诗','yuding','','[]','珠闕昆山遠，銀宮漲海懸。送君從此路，城郭幾千年。',48,'御定全唐詩/json/882.json','["珠闕昆山遠，銀宮漲海懸。送君從此路，城郭幾千年。", "雲霧含丹景，桑麻覆細田。笙歌未盡曲，風馭獨泠然。"]'),
('yuding-12','九城尋山水','薛曜','唐','御定全唐诗','yuding','','[]','菊浦桃源瞰九城，鸞歌鳳嘯忽將迎。千岩雜樹雲霞色，',40,'御定全唐詩/json/882.json','["菊浦桃源瞰九城，鸞歌鳳嘯忽將迎。千岩雜樹雲霞色，", "疑是昔年棲息地，山中日暮有餘情。"]'),
('yuding-13','邙山古意','薛曜','唐','御定全唐诗','yuding','','[]','昔掩佳城路，曾驚壑易遷。今接宜都裏，翻疑海作田。',96,'御定全唐詩/json/882.json','["昔掩佳城路，曾驚壑易遷。今接宜都裏，翻疑海作田。", "鏤鼎名應大，生金字不傳。風飆吹白日，羅綺拭黃泉。", "象鳳笙留國，成龍劍上天。長樂移新壟，咸陽失舊阡。", "川流徒漫漫，神理竟綿綿。佇見飛來鶴，沈嗟不學仙。"]'),
('yuding-14','鳳閣南廳槐樹半生死雖遇陽和終呈枯朽…緣情率爾為詠','李懷遠','唐','御定全唐诗','yuding','','[]','庭槐歲月深，半死尚抽心。葉少寧障日，枝疏不礙禽。',72,'御定全唐詩/json/882.json','["庭槐歲月深，半死尚抽心。葉少寧障日，枝疏不礙禽。", "帷幄諒無取，棟樑非所任。愧在龍樓側，羞處鳳池陰。", "未能辭雨露，猶得款衣簪。惜悲生意盡，空餘古木吟。"]'),
('yuding-15','和九月九日登慈恩寺浮圖應制','趙彥伯','唐','御定全唐诗','yuding','','[]','出豫垂佳節，憑高陟梵宮。皇心滿塵界，佛跡現虛空。',48,'御定全唐詩/json/882.json','["出豫垂佳節，憑高陟梵宮。皇心滿塵界，佛跡現虛空。", "日月宜長壽，天人得大通。喜聞題寶偈，受記莫由同。"]'),
('yuding-16','秋夜巫山','喬備','唐','御定全唐诗','yuding','','[]','巫峽裴回雨，陽臺淡蕩雲。江山空窈窕，朝暮自紛氳。',48,'御定全唐詩/json/882.json','["巫峽裴回雨，陽臺淡蕩雲。江山空窈窕，朝暮自紛氳。", "螢色寒秋露，猿啼清夜聞。誰憐夢魂遠，腸斷思紛紛。"]'),
('yuding-17','晦日與盧舍人同詣補闕城南林園','孫逖','唐','御定全唐诗','yuding','','[]','芳年正月晦，假日早朝回。欲盡三春賞，還欽二阮才。',48,'御定全唐詩/json/882.json','["芳年正月晦，假日早朝回。欲盡三春賞，還欽二阮才。", "柳迎郊騎入，花近□庭開。宛是人寰外，真情寓物來。"]'),
('yuding-18','贈劉藍田','盧象','唐','御定全唐诗','yuding','','[]','籬中犬迎吠，出屋候柴扉。歲晏輸井稅，山村人暮歸。',48,'御定全唐詩/json/882.json','["籬中犬迎吠，出屋候柴扉。歲晏輸井稅，山村人暮歸。", "晚田始家食，餘布成我衣。對此能無事，勞君問是非。"]'),
('yuding-19','清明日青龍寺上方','劉長卿','唐','御定全唐诗','yuding','','[]','上方偏可適，季月況堪過。遠近人都至，東西山色多。',48,'御定全唐詩/json/882.json','["上方偏可適，季月況堪過。遠近人都至，東西山色多。", "夕陽留徑草，新葉變庭柯。已度清明節，春愁如客何。"]'),
('yuding-20','羽山','蕭穎士','唐','御定全唐诗','yuding','','[]','九山方蕩潏，三考佇良材。夏祖何屯圮，遷殛此山隈。',36,'御定全唐詩/json/882.json','["九山方蕩潏，三考佇良材。夏祖何屯圮，遷殛此山隈。", "空餘下泉客，誰複辨黃能。"]'),
('yuding-21','游馬耳山','蕭穎士','唐','御定全唐诗','yuding','','[]','茲山表東服，遠近瞻其名。合遝盡溟漲，渾渾連太清。',168,'御定全唐詩/json/882.json','["茲山表東服，遠近瞻其名。合遝盡溟漲，渾渾連太清。", "我來疑初伏，幽路無炎精。流水出溪盡，覆蘿搖風輕。", "高深變氣候，俯仰暮天晴。入谷煙雨潤，登崖雲日明。", "乾坤正含養，種植總滋榮。草樹皆秀色，雛麋亂新聲。", "攀岩挹桂髓，洞穴拾瑤英。此地隱微徑，何人得長生。", "宿心尚葛許，彌願棲蓬瀛。太息宦名路，遲回忠孝情。", "還丹昧遠術，養素慚幽貞。安得從此去，悠然升玉京。"]'),
('yuding-22','□□□趙載同游焦湖夜歸作','蕭穎士','唐','御定全唐诗','yuding','','[]','□□將澤國，淜騰迎淮甸。東江輸大江，別流從此縣。',192,'御定全唐詩/json/882.json','["□□將澤國，淜騰迎淮甸。東江輸大江，別流從此縣。", "仙尉俯勝境，輕橈恣遊衍。自公暇有餘，微尚得所願。", "拈引間翰墨，風流盡歡宴。稍移井邑閑，始悅登眺便。", "遙岫逢應接，連塘乍回轉。劃然氣象分，萬頃行可見。", "波中峰一點，雲際帆千片。浩歎無端涯，孰知蘊虛變。", "往遊信不厭，畢景方未還。蘭□煙靄裏，延緣蒲稗間。", "勢隨風潮遠，心與□□閑。回見出浦月，雄光射東關。", "悠然蓬壺事，□□□衰顏。安得傲吏隱，彌年寓茲山。"]'),
('yuding-23','龍興觀金籙建醮','王翰','唐','御定全唐诗','yuding','','[]','泰山岩岩兮淩紫氛，中有群仙兮乘白雲，',18,'御定全唐詩/json/882.json','["泰山岩岩兮淩紫氛，中有群仙兮乘白雲，"]'),
('yuding-24','山中松','張鼎','唐','御定全唐诗','yuding','','[]','枝聳碧雲端，根侵蘚壁盤。幾經良匠顧，猶作散材看。',48,'御定全唐詩/json/882.json','["枝聳碧雲端，根侵蘚壁盤。幾經良匠顧，猶作散材看。", "雪積花開少，風多子落幹。空存後凋色，歲晚出林巒。"]'),
('yuding-25','庭前晚花開','李白','唐','御定全唐诗','yuding','','[]','西王母桃種我家，三千陽春始一花。',32,'御定全唐詩/json/882.json','["西王母桃種我家，三千陽春始一花。", "結實苦遲為人笑，攀折唧唧長咨嗟。"]'),
('yuding-26','漢州王大錄事宅作','杜甫','唐','御定全唐诗','yuding','','[]','南溪老病客，相見下肩輿。近發看烏帽，催蓴煮白魚。',48,'御定全唐詩/json/882.json','["南溪老病客，相見下肩輿。近發看烏帽，催蓴煮白魚。", "宅中平岸水，身外滿床書。憶爾才名叔，含淒意有餘。"]'),
('yuding-27','田家作','皇甫冉','唐','御定全唐诗','yuding','','[]','臥見高原燒，閑尋空穀泉。土膏消臘後，麥隴發春前。',144,'御定全唐詩/json/882.json','["臥見高原燒，閑尋空穀泉。土膏消臘後，麥隴發春前。", "藥驗桐君錄，心齊莊子篇。荒村三數處，衰柳百餘年。", "好就山僧去，時過野舍眠。汲流甯厭遠，蔔地本求偏。", "向子諳樵路，陶家置黍田。雪峰明晚景，風雁急寒天。", "且複冠名鶡，甯知冕戴蟬。問津夫子倦，荷蓧丈人賢。", "顧物皆從爾，求心正儻然。稽康懶慢性，只自戀風煙。"]'),
('yuding-28','寄劉方平','皇甫冉','唐','御定全唐诗','yuding','','[]','十年不出蹊林中，一朝結束甘從戎。嚴子持竿心寂曆，',72,'御定全唐詩/json/882.json','["十年不出蹊林中，一朝結束甘從戎。嚴子持竿心寂曆，", "每望南峰如對君，昨來不見多黃雲。石徑幽人何所在，", "天畔三秋空複情，袖中一字無由得。世人易合複易離，"]'),
('yuding-29','和中丞奉使承恩，還終南舊居','皇甫冉','唐','御定全唐诗','yuding','','[]','軒車尋舊隱，賓從滿郊園。蕭散煙霞興，殷勤故老言。',72,'御定全唐詩/json/882.json','["軒車尋舊隱，賓從滿郊園。蕭散煙霞興，殷勤故老言。", "謝公山不改，陶令菊猶存。苔蘚侵垂釣，松篁長閉門。", "風霜清吏事，江海諭君恩。祗召趨宣室，沉冥在一論。"]'),
('yuding-30','送令狐明府','皇甫冉','唐','御定全唐诗','yuding','','[]','行當臘候晚，共惜歲陰殘。聞道巴山遠，如何蜀路難。',48,'御定全唐詩/json/882.json','["行當臘候晚，共惜歲陰殘。聞道巴山遠，如何蜀路難。", "荒林藏積雪，亂石起驚湍。君有親人術，應令勞者安。"]'),
('yuding-31','同韓給事觀畢給事畫松石','皇甫冉','唐','御定全唐诗','yuding','','[]','海嶠微茫那得到，楚關迢遞心空憶。夕郎善畫岩間松，',88,'御定全唐詩/json/882.json','["海嶠微茫那得到，楚關迢遞心空憶。夕郎善畫岩間松，", "扶疏半映晚天青，凝澹全和曙雲黑。煙籠月照安可道，", "龍樓不競繁花吐，騎省偏宜遙夜直。羅浮道士訪移來，", "古槐衰柳寧足論，還對罘罳列行植。"]'),
('yuding-32','送從侄棲閑律師','皇甫冉','唐','御定全唐诗','yuding','','[]','能知出世法，詎有在家心。南院開門送，東山策杖尋。',48,'御定全唐詩/json/882.json','["能知出世法，詎有在家心。南院開門送，東山策杖尋。", "經年期故里，及夏到空林。念遠長勞望，朝朝草色深。"]'),
('yuding-33','舟中送李觀','皇甫冉','唐','御定全唐诗','yuding','','[]','江南近別亦依依，山晚川長客伴稀。',32,'御定全唐詩/json/882.json','["江南近別亦依依，山晚川長客伴稀。", "獨坐相思計行日，出門臨水望君歸。"]'),
('yuding-34','敕移橘栽','張彪','唐','御定全唐诗','yuding','','[]','南橘北為枳，古來豈虛言。徙植期不變，陰陽感君恩。',96,'御定全唐詩/json/882.json','["南橘北為枳，古來豈虛言。徙植期不變，陰陽感君恩。", "枝條皆宛然，本土封其根。及時望栽種，萬里繞花園。", "滋味豈聖心，實以憂黎元。暫勞致力重，永感貢獻煩。", "是嗟草木類，稟異於乾坤。願為王母桃，千歲奉至尊。"]'),
('yuding-0','晚霽登王六東閣','嚴維','唐','御定全唐诗','yuding','','[]','試上江樓望，初逢山雨晴。連空青嶂合，向晚白雲生。',48,'御定全唐詩/json/883.json','["試上江樓望，初逢山雨晴。連空青嶂合，向晚白雲生。", "俊美要殊觀，蕭條見遠情。情來不可極，日暮水流清。"]'),
('yuding-1','曲龍山歌','顧況','唐','御定全唐诗','yuding','','[]','曲龍丈人冠藕花，其顏色映光明砂。玉繩金枝有通籍，',244,'御定全唐詩/json/883.json','["曲龍丈人冠藕花，其顏色映光明砂。玉繩金枝有通籍，", "五嶽三山如一家。遙指叢霄遝靈島，島中曄曄無凡草。", "九仙傲倪折五芝，翠鳳白麟回異道。石台石鏡月長明，", "石洞石橋連上清。人間妻子見不識，拍雲揮手升天行。", "摩天截漢何瀟灑，四石五雲更上下。下方小兆更拜焉，", "願得騎雲作車馬。", "子欲居九夷，乘桴浮於海。聖人之意有所在，", "曲龍何在在海中。石室玉堂窅玲瓏，其下琛怪之所產，", "其上靈棲複無限。無風浪頂高屋脊，有風天晴翻海眼。", "願逐剛風騎吏旋，起居按摩參寥天。鳳凰頰骨流珠佩，", "孔雀尾毛張翠蓋。下看人界等蟲沙，夜宿層城阿母家。"]'),
('yuding-2','柳宜城鵲巢歌','顧況','唐','御定全唐诗','yuding','','[]','相公宅前楊柳樹，野鵲飛來複飛去。東家斫樹枝，',76,'御定全唐詩/json/883.json','["相公宅前楊柳樹，野鵲飛來複飛去。東家斫樹枝，", "西家斫樹枝。東家西家斫樹枝，發遣野鵲巢何枝。", "相君處分留野鵲，一月生得三個兒。相君長命複富貴，", "口舌貧窮徒爾為。"]'),
('yuding-3','道該上人院石竹花歌','顧況','唐','御定全唐诗','yuding','','[]','道該房前石竹叢，深淺紫，深淺紅。嬋娟灼爍委清露，',48,'御定全唐詩/json/883.json','["道該房前石竹叢，深淺紫，深淺紅。嬋娟灼爍委清露，", "小枝小葉飄香風。上人心中如鏡中，永日垂簾觀色空。"]'),
('yuding-4','九日','耿湋','唐','御定全唐诗','yuding','','[]','九日強遊登藻井，發稀那敢插茱萸。橫空過雨千峰出，',48,'御定全唐詩/json/883.json','["九日強遊登藻井，發稀那敢插茱萸。橫空過雨千峰出，", "大野新霜萬壑鋪。更望尊中菊花酒，殷勤能得幾回沽。"]'),
('yuding-5','青陽館望九子山','竇叔向','唐','御定全唐诗','yuding','','[]','蒼翠岧嶢上碧天，九峰遙落縣門前。毫芒映日千重樹，',64,'御定全唐詩/json/883.json','["蒼翠岧嶢上碧天，九峰遙落縣門前。毫芒映日千重樹，", "涓滴垂空萬丈泉。武帝南游曾駐蹕，始皇東幸亦祈年。", "雲祠絕跡終難訪，唯有猿聲到客邊。"]'),
('yuding-6','青出藍','王季友1','唐','御定全唐诗','yuding','','[]','芳藍滋匹帛，人力半天經。浸潤加新氣，光輝勝本清。',48,'御定全唐詩/json/883.json','["芳藍滋匹帛，人力半天經。浸潤加新氣，光輝勝本清。", "還同冰出水，不共草為螢。翻覆衣襟上，偏知造化靈。"]'),
('yuding-7','皇帝移晦日為中和節','王季友1','唐','御定全唐诗','yuding','','[]','皇心不向晦，改節號中和。淑氣同風景，嘉名別詠歌。',72,'御定全唐詩/json/883.json','["皇心不向晦，改節號中和。淑氣同風景，嘉名別詠歌。", "湔裙移舊俗，賜尺下新科。曆象千年正，酺醵四海多。", "花隨春令發，鴻度歲陽過。天地齊休慶，歡聲欲蕩波。"]'),
('yuding-8','送劉南史往杭州拜覲別駕叔','劉商','唐','御定全唐诗','yuding','','[]','兄弟飄零自長年，見君眉白轉相憐。清揚似玉須勤學，',64,'御定全唐詩/json/883.json','["兄弟飄零自長年，見君眉白轉相憐。清揚似玉須勤學，", "富貴由人不在天。萬里榛蕪迷舊國，兩河烽火複相連。", "林中若使題書信，但問漳濱訪客船。"]'),
('yuding-9','和汴州令狐相公白菊','楊巨源','唐','御定全唐诗','yuding','','[]','兔園春欲盡，別有一叢芳。直似窮陰雪，全輕向曉霜。',96,'御定全唐詩/json/883.json','["兔園春欲盡，別有一叢芳。直似窮陰雪，全輕向曉霜。", "凝暉侵桂魄，晶彩奪螢光。素萼迎風舞，銀房泫露香。", "水晶簾不隔，雲母扇韜鋩。紈袖呈瑤瑟，冰容啟玉堂。", "今來碧油下，知自白雲鄉。留此非吾土，須移鳳沼傍。"]'),
('yuding-10','贈陳判官求子花詩','楊巨源','唐','御定全唐诗','yuding','','[]','油地輕綃碧且紅，須憐纖手是良工。能生麗思千花外，',64,'御定全唐詩/json/883.json','["油地輕綃碧且紅，須憐纖手是良工。能生麗思千花外，", "善點穠姿五彩中。子細傳看臨霽景，殷勤持贈及春風。", "若將江上迎桃葉，一帖何妨錦繡同。"]'),
('yuding-11','同諸公過福先寺律院宣上人房','歐陽詹','唐','御定全唐诗','yuding','','[]','律座下朝講，晝門猶掩關。叨同靜者來，正值高雲閑。',72,'御定全唐詩/json/883.json','["律座下朝講，晝門猶掩關。叨同靜者來，正值高雲閑。", "寂爾方丈內，瑩然虛白間。千燈智慧心，片玉清羸顏。", "松色落深井，竹陰寒小山。晤言流曦晚，惆悵歸人寰。"]'),
('yuding-12','城西別元九','白居易','唐','御定全唐诗','yuding','','[]','城西三月三十日，別友辭春兩恨多。',32,'御定全唐詩/json/883.json','["城西三月三十日，別友辭春兩恨多。", "帝裏卻歸猶寂寞，通州獨去又如何。"]'),
('yuding-13','陳家紫藤花下贈周判官','白居易','唐','御定全唐诗','yuding','','[]','藤花無次第，萬朵一時開。不是周從事，何人喚我來。',24,'御定全唐詩/json/883.json','["藤花無次第，萬朵一時開。不是周從事，何人喚我來。"]'),
('yuding-14','遊小洞庭','白居易','唐','御定全唐诗','yuding','','[]','湖山上頭別有湖，芰荷香氣占仙都。夜含星斗分幹象，',64,'御定全唐詩/json/883.json','["湖山上頭別有湖，芰荷香氣占仙都。夜含星斗分幹象，", "曉映雷雲作畫圖。風動綠蘋天上浪，鳥棲寒照月中烏。", "若非神物多靈跡，爭得長年冬不枯。"]'),
('yuding-15','傷蔡處士','楊衡','唐','御定全唐诗','yuding','','[]','篋中遺草是琅玕，對此令人灑淚看。三徑尚疑行跡在，',64,'御定全唐詩/json/883.json','["篋中遺草是琅玕，對此令人灑淚看。三徑尚疑行跡在，", "數螢猶自映書殘。晨光不借泉門曉，暝色空添隴樹寒。", "欲問皇天天更遠，有才無命說應難。"]'),
('yuding-16','奉使過石門瀑布','丘丹','唐','御定全唐诗','yuding','','[]','溪上望懸泉，耿耿雲中見。披榛上岩巘，絕壁正東面。',132,'御定全唐詩/json/883.json','["溪上望懸泉，耿耿雲中見。披榛上岩巘，絕壁正東面。", "千仞瀉聯珠，一潭噴飛霰。嵯潨滿山響，坐覺炎氛變。", "照日類虹蜺，從風似綃練。靈奇既天造，惜處窮海甸。", "吾祖昔登臨，謝公亦遊衍。王程懼淹泊，下磴空延眷。", "千里雷尚聞，巒回樹蔥蒨。奔波恭賤役，探討愧前彥。", "永欲洗塵纓，終當愜茲願。"]'),
('yuding-17','秋夕宿石門館','丘丹','唐','御定全唐诗','yuding','','[]','暝從石門宿，搖落四岩空。潭月漾山足，天河瀉澗中。',48,'御定全唐詩/json/883.json','["暝從石門宿，搖落四岩空。潭月漾山足，天河瀉澗中。", "杉松寒似雨，猿鳥夕驚風。獨臥不成寐，蒼然想謝公。"]'),
('yuding-18','廬山瀑布','張碧','唐','御定全唐诗','yuding','','[]','誰將織女機頭練，貼出青山碧雲面。造化工夫不等閒，',128,'御定全唐詩/json/883.json','["誰將織女機頭練，貼出青山碧雲面。造化工夫不等閒，", "剪破澄江凝一片。怪來洞口流嗚咽，怕見三冬晝飛雪。", "石鏡無光相對愁，漫漫頂上沉秋月。爭得陽烏照山北，", "放出青天豁胸臆。黛花新染插天風，驀吐中心爛銀色。", "五月六月暑雲飛，閣門遠看澄心機。參差碎碧落岩畔，", "梅花亂擺當風散。"]'),
('yuding-19','林書記薔薇','張碧','唐','御定全唐诗','yuding','','[]','東風折盡諸花卉，是個亭台冷如水。黃鸝舌滑跳柳陰，',144,'御定全唐詩/json/883.json','["東風折盡諸花卉，是個亭台冷如水。黃鸝舌滑跳柳陰，", "教看薔薇吐金蕊。雙成湧出琉璃宮，天香闊罩紅熏籠。", "西施曉下吳王殿，亂拋嬌臉新勻濃。瑤姬學繡流蘇幔，", "綠夾殷紅垂錦段。炎洲吹落滿汀雲，阮瑀庭前裝一半。", "醉且書懷還複吟，蜀箋影裏霞光侵。秦娥晚憑欄幹立，", "柔枝墜落青羅襟。殷勤無波綠池水，為君作鏡開妝蕊。"]'),
('yuding-20','答友人新栽松','張碧','唐','御定全唐诗','yuding','','[]','石門新長青龍髯，虯身宛轉雲光黏。聞君愛我幽崖前，',112,'御定全唐詩/json/883.json','["石門新長青龍髯，虯身宛轉雲光黏。聞君愛我幽崖前，", "十株五株寒霜天。越溪老僧頭削雪，曾雲手植當庭月。", "三十年來遮火雲，涼風五月生空門。願君栽於清澗泉，", "貞姿莫迓夭桃妍。□□易開還易落，貞姿鬱鬱長依然。", "山童懶上孤峰巔，當窗劃破屏風煙。"]'),
('yuding-21','金錢花','陳翥','唐','御定全唐诗','yuding','','[]','嫋露牽風夾瘦莎，一星星火遍窠窠。',64,'御定全唐詩/json/883.json','["嫋露牽風夾瘦莎，一星星火遍窠窠。", "閑門永巷新秋裏，幸不傷廉莫怕多。", "古蘚寒蕪讓品流，小齋多謝伴清幽。", "若教夷甫門前種，也是無多過一秋。"]'),
('yuding-22','山居雨霽即事','長孫佐輔','唐','御定全唐诗','yuding','','[]','結茅蒼嶺下，自與喧卑隔。況值雷雨晴，郊原轉岑寂。',144,'御定全唐詩/json/883.json','["結茅蒼嶺下，自與喧卑隔。況值雷雨晴，郊原轉岑寂。", "出門看反照，繞屋殘溜滴。古路絕人行，荒陂響螻蟈。", "籬崩瓜豆蔓，圃壤牛羊跡。斷續古祠鴉，高低遠村笛。", "喜聞東皋潤，欲往未通屐。杖策試危橋，攀蘿瞰苔壁。", "鄰翁夜相訪，緩酌聊跂石。新月出汙尊，浮雲在中舄。", "常隳腐儒操，謬習經邦畫。有待時未知，非關慕沮溺。"]'),
('yuding-23','秋日登山','長孫佐輔','唐','御定全唐诗','yuding','','[]','逐勝不怯寒，秋山閑獨登。依稀小徑通，深處逢來僧。',48,'御定全唐詩/json/883.json','["逐勝不怯寒，秋山閑獨登。依稀小徑通，深處逢來僧。", "側石擁寒溜，欹松懸古藤。明書問知友，興詠將誰能。"]'),
('yuding-24','自京師將赴黔南','竇鞏','唐','御定全唐诗','yuding','','[]','風雨荊州二月天，問人須雇峽中船。',32,'御定全唐詩/json/883.json','["風雨荊州二月天，問人須雇峽中船。", "西南一望雲和水，猶道黔南有四千。"]'),
('yuding-25','中秋夜洞庭圓月','姚合','唐','御定全唐诗','yuding','','[]','素月閑秋景，騷人泛洞庭。滄波正澄霽，涼葉未飄零。',72,'御定全唐詩/json/883.json','["素月閑秋景，騷人泛洞庭。滄波正澄霽，涼葉未飄零。", "練彩凝葭菼，霜容靜杳冥。曉棲河畔鶴，宵映渚邊螢。", "圓彩含珠魄，微飆發桂馨。誰憐采蘋客，此夜宿孤汀。"]'),
('yuding-26','濉陽行','李涉','唐','御定全唐诗','yuding','','[]','黃昏日暮驅羸馬，夜宿濉陽烽火下。此地新經殺戮來，',128,'御定全唐詩/json/883.json','["黃昏日暮驅羸馬，夜宿濉陽烽火下。此地新經殺戮來，", "墟落無煙空碎瓦。層冰塞斷隋朝水，一道銀河貫千里。", "愁心翻覆夢難成，病僕呻吟呼不起。泗水三千招義軍，", "本是征戰邀殊勳。十年麾下蓄壯氣，一朝此地為愁人。", "昨日太陽回照燭，轉見天心重含育。早晚東風的發生，", "古堤春草年年綠。"]'),
('yuding-27','六歎','李涉','唐','御定全唐诗','yuding','','[]','蓬萊島邊采珠客，西望人寰星漢隔。千重疊浪聳雲高，',272,'御定全唐詩/json/883.json','["蓬萊島邊采珠客，西望人寰星漢隔。千重疊浪聳雲高，", "萬里平沙連月白。海中洞穴尋難極，水底鮫人半相識。", "玄蚌初開影暫明，驪龍欲近威難逼。辛苦風濤白首期，", "得珠卻恨求珠時。隋侯歿世幾千載，只今薄俗空嗤嗤。", "燕王愛賢築金台，四方豪俊承風來。秦王燒書殺儒客，", "肘腋之中千里隔。去年八月幽並道，昭王陵邊哭秋草。", "今年二月游函關，秦家城外悲河山。河上山邊車馬路，", "殘日青煙五陵樹。", "關東病儒客梁城，五歲十回逢亂兵。燒人之家食人肉，", "狼虎熾心都未足。城裏愁雲不開城，城頭野草春還綠。", "五十餘年忠烈臣，臨難守節羞謀身。堂上英髦沉白刃，", "門前輿隸乘朱輪。千古傷心汴河水，陰天落日悲風起。"]'),
('yuding-28','卻歸巴陵途中走筆寄唐知言','李涉','唐','御定全唐诗','yuding','','[]','去年臘月來夏口，黑風白浪打頭吼。櫓聲軋軋搖不前，',352,'御定全唐詩/json/883.json','["去年臘月來夏口，黑風白浪打頭吼。櫓聲軋軋搖不前，", "看他撩亂張帆走。逾月始到鸚鵡洲，嗚嗚暮角喧城頭。", "逡巡未得見官長，夢寢但覺生愁憂。軍中賢倅李監察，", "人馬曉來兼手劄。教令參謁禮數全，頭頭要處相稱掣。", "唐氏一門今五龍，聲華殷殷皆如鐘。就中十一最年少，", "別有俊氣橫心胸。巧綴五言才刮骨，卻怕柱天身硉矹。", "後輩無勞續出頭，坳塘不合窺溟渤。君家三兄舊山侶，", "方寸久來常許與。不覺淹留兩月餘，風光漫爛生洲渚。", "宇文文學儒家子，竹繞書齋花映水。醉舞狂歌此地多，", "有時酩酊扶還起。猥蒙方伯憐饑貧，假名許得陪諸賓。", "酒家債負有填日，恣意頗敢排青緡。余瞿二家同愛客，", "園蔬任遣奴人摘。野狐泉頭銀葉方，一別十年今再覿。", "更有風流歙奴子，能將盤帕來欺爾。白馬青袍豁眼明，", "許他真是查郎髓。良會芳時難再來，隙光電影長相催。", "扁舟惆悵人南去，目斷江天凡幾回。"]'),
('yuding-29','山中五無奈何','李涉','唐','御定全唐诗','yuding','','[]','無奈落葉何，紛紛滿衰草。疾來無氣力，擁戶不能掃。',144,'御定全唐詩/json/883.json','["無奈落葉何，紛紛滿衰草。疾來無氣力，擁戶不能掃。", "欲訪雲外人，都迷上山道。", "無奈澗水何，喧喧夜鳴石。疏林透斜月，散亂金光滴。", "欲訪澗底人，路窮潭水碧。", "無奈阿鼎何，嬌啼索梨栗。柴門正風雨，千向千回出。", "欲識老病心，賴渠將過日。", "無奈梅花何，滿岩光似雪。春風總未至，獨自驚時節。", "欲見惆悵心，又看花上月。"]'),
('yuding-30','江南雜題','張祜','唐','御定全唐诗','yuding','','[]','積潦池新漲，頹垣址舊高。怒蛙橫飽腹，鬥雀墮輕毛。',48,'御定全唐詩/json/883.json','["積潦池新漲，頹垣址舊高。怒蛙橫飽腹，鬥雀墮輕毛。", "碧瘦三棱草，紅鮮百葉桃。幽棲日無事，痛飲讀離騷。"]'),
('yuding-31','賦得福州白竹扇子','張祜','唐','御定全唐诗','yuding','','[]','金泥小扇謾多情，未勝南工巧織成。藤縷雪光纏柄滑，',64,'御定全唐詩/json/883.json','["金泥小扇謾多情，未勝南工巧織成。藤縷雪光纏柄滑，", "篾鋪銀薄露花輕。清風坐向羅衫起，明月看從玉手生。", "猶賴早時君不棄，每憐初作合歡名。"]'),
('yuding-32','潤州楊別駕宅送蔣侍禦收兵歸揚州','張祜','唐','御定全唐诗','yuding','','[]','冷氣清金虎，兵威壯鐵冠。揚旌川色暗，吹角水風寒。',48,'御定全唐詩/json/883.json','["冷氣清金虎，兵威壯鐵冠。揚旌川色暗，吹角水風寒。", "人對輜輧醉，花垂睥睨殘。羨歸丞相閣，空望舊門闌。"]'),
('yuding-33','觀泗州李常侍打球','張祜','唐','御定全唐诗','yuding','','[]','日出樹煙紅，開場畫鼓雄。驟騎鞍上月，輕撥鐙前風。',72,'御定全唐詩/json/883.json','["日出樹煙紅，開場畫鼓雄。驟騎鞍上月，輕撥鐙前風。", "鬥轉時乘勢，旁捎乍迸空。等來低背手，爭得旋分鬃。", "遠射門斜入，深排馬迥通。遙知三殿下，長恨出征東。"]'),
('yuding-34','閒居','張祜','唐','御定全唐诗','yuding','','[]','僻巷新苔遍，空庭弱柳垂。井欄防稚子，盆水試鵝兒。',48,'御定全唐詩/json/883.json','["僻巷新苔遍，空庭弱柳垂。井欄防稚子，盆水試鵝兒。", "喜客加籩食，邀僧長路棋。未能拋世事，除此更何為。"]'),
('yuding-0','渡吳江','杜牧','唐','御定全唐诗','yuding','','[]','堠館人稀夜更長，姑蘇城遠樹蒼蒼。江湖潮落高樓迥，',40,'御定全唐詩/json/884.json','["堠館人稀夜更長，姑蘇城遠樹蒼蒼。江湖潮落高樓迥，", "文園詩侶應多思，莫醉笙歌掩華堂。"]'),
('yuding-1','元日觀朝','厲玄','唐','御定全唐诗','yuding','','[]','玉座臨新歲，朝盈萬國人。火連雙闕曉，仗列五門春。',48,'御定全唐詩/json/884.json','["玉座臨新歲，朝盈萬國人。火連雙闕曉，仗列五門春。", "瑞雪銷鴛瓦，祥光在日輪。天顏不敢視，稱慶拜空頻。"]'),
('yuding-2','六月','趙璜','唐','御定全唐诗','yuding','','[]','六月火雲散，蟬聲鳴樹梢。秋風豈便借，客思已蕭條。',48,'御定全唐詩/json/884.json','["六月火雲散，蟬聲鳴樹梢。秋風豈便借，客思已蕭條。", "傾國三年別，煙霞一路遙。行人斷消息，更上灞陵橋。"]'),
('yuding-3','樊川寒食','喻鳧','唐','御定全唐诗','yuding','','[]','新松□綠草，古柏翳黃沙。佩珂客驚鳥，綺羅人間花。',48,'御定全唐詩/json/884.json','["新松□綠草，古柏翳黃沙。佩珂客驚鳥，綺羅人間花。", "蹙塵南北馬，碾石去來車。川晚悲風動，墳前碎紙斜。"]'),
('yuding-4','芍藥','潘鹹','唐','御定全唐诗','yuding','','[]','閑來竹亭賞，賞極蕊珠宮。葉已盡餘翠，花才半展紅。',48,'御定全唐詩/json/884.json','["閑來竹亭賞，賞極蕊珠宮。葉已盡餘翠，花才半展紅。", "媚欺桃李色，香奪綺羅風。每到春殘日，芳華處處同。"]'),
('yuding-5','晚步','劉得仁','唐','御定全唐诗','yuding','','[]','野步晚悠悠，山光澹早秋。遠空淪日腳，多稼沒人頭。',48,'御定全唐詩/json/884.json','["野步晚悠悠，山光澹早秋。遠空淪日腳，多稼沒人頭。", "古木蟬齊噪，深塍水慢流。幽居回不近，秋策卻堪愁。"]'),
('yuding-6','村晚閒步','劉得仁','唐','御定全唐诗','yuding','','[]','緩步出居處，過原邊雁行。夕陽投草木，遠水映蒼茫。',48,'御定全唐詩/json/884.json','["緩步出居處，過原邊雁行。夕陽投草木，遠水映蒼茫。", "野寺同蟾宿，雲溪劚藥嘗。蕭條霜景暮，極目盡堪傷。"]'),
('yuding-7','冬日題興善寺崔律師院孤松','劉得仁','唐','御定全唐诗','yuding','','[]','為此疏名路，頻來訪遠公。孤標宜雪後，每見憶山中。',48,'御定全唐詩/json/884.json','["為此疏名路，頻來訪遠公。孤標宜雪後，每見憶山中。", "靜影生幽蘚，寒聲入迥空。何年植茲地，曉夕動清風。"]'),
('yuding-8','題新栽小松','劉得仁','唐','御定全唐诗','yuding','','[]','滿庭蕭颯皆凡木，豈得颼飀似石溪。雪夜枝柯疑畫出，',40,'御定全唐詩/json/884.json','["滿庭蕭颯皆凡木，豈得颼飀似石溪。雪夜枝柯疑畫出，", "卻向舊山尋得處，白雲根蕟覓應迷。"]'),
('yuding-9','栽松','劉得仁','唐','御定全唐诗','yuding','','[]','翠色凜空庭，披衣獨繞行。取從山頂嶮，栽得道心生。',48,'御定全唐詩/json/884.json','["翠色凜空庭，披衣獨繞行。取從山頂嶮，栽得道心生。", "未弱幽泉韻，焉論別木聲。霜天殘月在，轉影入池清。"]'),
('yuding-10','十日菊','薛瑩','唐','御定全唐诗','yuding','','[]','昨日尊前折，萬人酣曉香。今朝籬下見，滿地委殘陽。',48,'御定全唐詩/json/884.json','["昨日尊前折，萬人酣曉香。今朝籬下見，滿地委殘陽。", "得失片時痛，榮枯一歲傷。未將同腐草，猶更有重霜。"]'),
('yuding-11','赴南巴留別蘇台知己','賈島','唐','御定全唐诗','yuding','','[]','人過梅嶺上，歲歲北風寒。落日孤舟去，青山萬里看。',48,'御定全唐詩/json/884.json','["人過梅嶺上，歲歲北風寒。落日孤舟去，青山萬里看。", "猿聲湘水靜，草色洞庭寬。已料生涯事，只應持釣竿。"]'),
('yuding-12','紅薔薇','莊南傑','唐','御定全唐诗','yuding','','[]','九天碎霞明澤國，造化工夫潛剪刻。翠葉長眉約細枝，',40,'御定全唐詩/json/884.json','["九天碎霞明澤國，造化工夫潛剪刻。翠葉長眉約細枝，", "謝豹聲催麥隴秋，熏風吹落猩猩血。"]'),
('yuding-13','曉歌','莊南傑','唐','御定全唐诗','yuding','','[]','鶤雞哭樹星河轉，海上金烏翅如電。嫦娥斂發綰雲頭，',40,'御定全唐詩/json/884.json','["鶤雞哭樹星河轉，海上金烏翅如電。嫦娥斂發綰雲頭，", "魏宮鐘動繡窗明，夢娥驚對殘燈立。"]'),
('yuding-14','春草歌','莊南傑','唐','御定全唐诗','yuding','','[]','漠漠綿綿幾多思，無言領得春風意。花裁小錦繡晴空，',40,'御定全唐詩/json/884.json','["漠漠綿綿幾多思，無言領得春風意。花裁小錦繡晴空，", "離人不忍到此處，淚娥滴盡雙真珠。"]'),
('yuding-15','古松歌','莊南傑','唐','御定全唐诗','yuding','','[]','山上山下松，森沈翠蓋煙。龜鱗犀甲鎖支體，',42,'御定全唐詩/json/884.json','["山上山下松，森沈翠蓋煙。龜鱗犀甲鎖支體，", "拏天攫地數千尺，恐作雲雨歸維嵩。維嵩成大廈，"]'),
('yuding-16','蒲中霽後晚望','薛能','唐','御定全唐诗','yuding','','[]','河邊霽色無人見，身帶春風立岸頭。',32,'御定全唐詩/json/884.json','["河邊霽色無人見，身帶春風立岸頭。", "濁水茫茫有何意，日斜還向古蒲州。"]'),
('yuding-17','龍門八韻','薛能','唐','御定全唐诗','yuding','','[]','河浸華夷闊，山橫宇宙雄。高波萬丈瀉，夏禹幾年功。',96,'御定全唐詩/json/884.json','["河浸華夷闊，山橫宇宙雄。高波萬丈瀉，夏禹幾年功。", "川迸晴明雨，林生旦暮風。人看翻進退，鳥性斷西東。", "氣逐雲歸海，聲驅石落空。近身毛乍豎，當面語難通。", "沸沫歸何處，盤渦傍此中。從來化鬐者，攀去路應同。"]'),
('yuding-18','新雪','薛能','唐','御定全唐诗','yuding','','[]','細落粗和忽複繁，頓清朝市不聞喧。天迷皓色風何亂，',40,'御定全唐詩/json/884.json','["細落粗和忽複繁，頓清朝市不聞喧。天迷皓色風何亂，", "閑吟只愛煎茶澹，斡破平光向近軒。"]'),
('yuding-19','送判官赴京','薛能','唐','御定全唐诗','yuding','','[]','闕下情偏已絕稀，天涯身遠複相依。庭花每對從容落，',40,'御定全唐詩/json/884.json','["闕下情偏已絕稀，天涯身遠複相依。庭花每對從容落，", "青雲若遇交親話，白璧無心待發揮。"]'),
('yuding-20','溪東岑望天都山','朱景玄','唐','御定全唐诗','yuding','','[]','目望浮山丘，梯雲上東岑。群峰爭入冥，巉巉生太陰。',96,'御定全唐詩/json/884.json','["目望浮山丘，梯雲上東岑。群峰爭入冥，巉巉生太陰。", "昔賢此升仙，結構窮聳深。未曉日先照，當晝色半沉。", "風泉雪霜飛，雲樹瓊玉林。大道非閉隔，無路不可尋。", "窺鏡澄夙慮，望壇起敬心。一從呼子安，永絕金玉音。"]'),
('yuding-21','夜行次東關逢魏扶東歸','許渾','唐','御定全唐诗','yuding','','[]','南北斷蓬飄，長亭酒一瓢。殘雲歸太華，疏雨過中條。',48,'御定全唐詩/json/884.json','["南北斷蓬飄，長亭酒一瓢。殘雲歸太華，疏雨過中條。", "樹色隨關迥，河聲入塞遙。勞歌此分首，風急馬蕭蕭。"]'),
('yuding-22','南遊湘漢寄友人','李頻','唐','御定全唐诗','yuding','','[]','南去遠三京，三湘五月行。巴江雪水下，楚澤火雲生。',48,'御定全唐詩/json/884.json','["南去遠三京，三湘五月行。巴江雪水下，楚澤火雲生。", "向野聊中飲，乘涼探暮程。離懷不可說，已近峽猿聲。"]'),
('yuding-23','送劉山人歸洞庭','李頻','唐','御定全唐诗','yuding','','[]','卻共孤雲去，高眠最上峰。半湖乘早月，中路入疏鐘。',48,'御定全唐詩/json/884.json','["卻共孤雲去，高眠最上峰。半湖乘早月，中路入疏鐘。", "秋盡蟲聲急，夜深山雨重。當時同隱者，分得幾株松。"]'),
('yuding-24','早發','李郢','唐','御定全唐诗','yuding','','[]','野店星河在，行人道路長。孤燈憐宿處，斜月厭新裝。',48,'御定全唐詩/json/884.json','["野店星河在，行人道路長。孤燈憐宿處，斜月厭新裝。", "草色多寒露，蟲聲似故鄉。清秋無限恨，殘菊過重陽。"]'),
('yuding-25','題惠山','李郢','唐','御定全唐诗','yuding','','[]','乳洞陰陰碧澗連，杉松六月冷無蟬。',32,'御定全唐詩/json/884.json','["乳洞陰陰碧澗連，杉松六月冷無蟬。", "黃昏飛盡白蝙蝠，茶火數星山寂然。"]'),
('yuding-26','雨中看山榴落花','李郢','唐','御定全唐诗','yuding','','[]','山榴逼砌栽，山火一團開。盡日風兼雨，春渠擁作堆。',24,'御定全唐詩/json/884.json','["山榴逼砌栽，山火一團開。盡日風兼雨，春渠擁作堆。"]'),
('yuding-27','寄友人乞菊栽','李郢','唐','御定全唐诗','yuding','','[]','藥闌經雨正堪鋤，白菊煩君乞數株。潘嶽賦中芳思在，',40,'御定全唐詩/json/884.json','["藥闌經雨正堪鋤，白菊煩君乞數株。潘嶽賦中芳思在，", "□子成仙縱難學，九秋思看集鳩雛。"]'),
('yuding-28','江邊柳','李郢','唐','御定全唐诗','yuding','','[]','東風晴色掛闌幹，眉葉初晴畏曉寒。',32,'御定全唐詩/json/884.json','["東風晴色掛闌幹，眉葉初晴畏曉寒。", "江上別筵終日有，綠條春在長應難。"]'),
('yuding-29','鵝兒','李郢','唐','御定全唐诗','yuding','','[]','臘後閑行村舍邊，黃鵝清水真可憐。何窮散亂隨新草，',40,'御定全唐詩/json/884.json','["臘後閑行村舍邊，黃鵝清水真可憐。何窮散亂隨新草，", "風吹楚澤蒹葭暮，看下寒溪逐去船。"]'),
('yuding-30','酬友人春暮寄枳花茶','李郢','唐','御定全唐诗','yuding','','[]','昨日東風吹枳花，酒醒春晚一甌茶。如雲正護幽人塹，',40,'御定全唐詩/json/884.json','["昨日東風吹枳花，酒醒春晚一甌茶。如雲正護幽人塹，", "相如病渴今全校，不羨生台白頸鴉。"]'),
('yuding-31','郢自街西醉歸馬鞭墜失崔員外、起秘書…抒短章仰酬珍錫','李郢','唐','御定全唐诗','yuding','','[]','蜀岩陰面冷冥冥，偃雪欺霜半露青。銛刃剪裁多鵲媚，',40,'御定全唐詩/json/884.json','["蜀岩陰面冷冥冥，偃雪欺霜半露青。銛刃剪裁多鵲媚，", "蘭省貴寮蓬閣吏，一時緘贈到雲亭。"]'),
('yuding-32','即目','李郢','唐','御定全唐诗','yuding','','[]','自笑騰騰者，非憨又不狂。何為跧似鼠，而複怯於獐。',96,'御定全唐詩/json/884.json','["自笑騰騰者，非憨又不狂。何為跧似鼠，而複怯於獐。", "落拓無生計，伶俜戀酒鄉。冥搜得詩窟，偶戰出文場。", "愛雪愁冬盡，懷人覺夜長。石樓多爽氣，檉案有餘香。", "運去非關拙，時來不在忙。平生兩閒暇，孤趣滿滄浪。"]'),
('yuding-33','羅敷東館亭下流泉雲至前山擁咽經歲移時掬弄惆悵成章','李郢','唐','御定全唐诗','yuding','','[]','看山亭下小鳴泉，嗚咽難通亦可憐。',32,'御定全唐詩/json/884.json','["看山亭下小鳴泉，嗚咽難通亦可憐。", "惆悵無人為疏鑿，擁愁含恨過年年。"]'),
('yuding-34','白櫻樹','于武陵','唐','御定全唐诗','yuding','','[]','記得花開雪滿枝，和蜂和蝶帶花移。',32,'御定全唐詩/json/884.json','["記得花開雪滿枝，和蜂和蝶帶花移。", "如今花落遊蜂去，空作主人惆悵詩。"]'),
('yuding-35','過南城縣麻姑山','崔櫓','唐','御定全唐诗','yuding','','[]','似前如卻玉堆堆，薄帶輕煙翠好裁。斜倚兔鉤孤影伴，',120,'御定全唐詩/json/884.json','["似前如卻玉堆堆，薄帶輕煙翠好裁。斜倚兔鉤孤影伴，", "驚訝昔人曾羽化，此中爭不接瑤台。", "詩手難題畫手慚，淺青濃碧疊東南。塵愁世界忙心在，", "家風負荷須名宦，可惜千峰綠似藍。", "差煙危碧半斜暉，何代仙人此羽飛。高袖鎮長寒柏暗，", "聲利系身家繫念，今生辜負六銖衣。"]'),
('yuding-36','和友人題僧院薔薇花三首','崔櫓','唐','御定全唐诗','yuding','','[]','何人移得在禪家，瑟瑟枝條簇簇霞。爭那寂寥埋草暗，',120,'御定全唐詩/json/884.json','["何人移得在禪家，瑟瑟枝條簇簇霞。爭那寂寥埋草暗，", "看取老僧齊物意，一般拋擲等凡花。", "忍委芳心此地開，似霞顏色苦低回。風驚少女偷香去，", "三清上客知惆悵，勸我春醪一兩杯。", "露香如醉態如慵，斜壓危闌草色中。試問更誰過野寺，", "一日幾回來又去，不能容易舍深紅。"]'),
('yuding-37','春晚泊船江村','崔櫓','唐','御定全唐诗','yuding','','[]','芳草青青古渡頭，漁家住處暫維舟。殘花半樹悄無語，',40,'御定全唐詩/json/884.json','["芳草青青古渡頭，漁家住處暫維舟。殘花半樹悄無語，", "自憐愛失心期約，看取花時更遠遊。"]'),
('yuding-38','柳','崔櫓','唐','御定全唐诗','yuding','','[]','風慢日遲遲，拖煙拂水時。惹將千萬恨，系在短長枝。',48,'御定全唐詩/json/884.json','["風慢日遲遲，拖煙拂水時。惹將千萬恨，系在短長枝。", "骨軟張郎瘦，腰輕楚女饑。故園歸未得，多少斷腸思。"]'),
('yuding-39','蓮花','崔櫓','唐','御定全唐诗','yuding','','[]','影欹晴浪勢欹煙，恨態緘言日抵年。輕霧曉和香積飯，',40,'御定全唐詩/json/884.json','["影欹晴浪勢欹煙，恨態緘言日抵年。輕霧曉和香積飯，", "何限斷腸名不得，倚風嬌怯醉腰偏。"]'),
('yuding-40','殘蓮花','崔櫓','唐','御定全唐诗','yuding','','[]','倚風無力減香時，涵露如啼臥翠池。',64,'御定全唐詩/json/884.json','["倚風無力減香時，涵露如啼臥翠池。", "金谷樓前馬嵬下，世間殊色一般悲。", "不耐高風怕冷煙，瘦紅欹委倒青蓮。", "無人解把無塵袖，盛取殘香盡日憐。"]'),
('yuding-41','惜蓮花','崔櫓','唐','御定全唐诗','yuding','','[]','半塘前日染來紅，瘦盡金方昨夜風。留樣最嗟無巧筆，',40,'御定全唐詩/json/884.json','["半塘前日染來紅，瘦盡金方昨夜風。留樣最嗟無巧筆，", "魂斷舊溪憔悴態，冷煙殘粉楚台東。"]'),
('yuding-42','岳陽雲夢亭看蓮花','崔櫓','唐','御定全唐诗','yuding','','[]','似醉如慵一水心，斜陽欲暝彩雲深。清明月照羞無語，',40,'御定全唐詩/json/884.json','["似醉如慵一水心，斜陽欲暝彩雲深。清明月照羞無語，", "當時為汝題詩遍，此地依前泥苦吟。"]'),
('yuding-43','村路菊花','崔櫓','唐','御定全唐诗','yuding','','[]','嫋風驚未定，溪影晚來寒。不得重陽節，虛將滿把看。',48,'御定全唐詩/json/884.json','["嫋風驚未定，溪影晚來寒。不得重陽節，虛將滿把看。", "神仙誰采掇，煙雨惜凋殘。牧豎樵童看，應教愛爾難。"]'),
('yuding-44','題山驛新桐花','崔櫓','唐','御定全唐诗','yuding','','[]','雨餘煙膩暖香浮，影暗斜陽古驛樓。丹鳳總巢阿閣去，',40,'御定全唐詩/json/884.json','["雨餘煙膩暖香浮，影暗斜陽古驛樓。丹鳳總巢阿閣去，", "長日老春看落盡，野禽閑哢碧悠悠。"]'),
('yuding-45','山路木芙蓉','崔櫓','唐','御定全唐诗','yuding','','[]','不向橫塘泥裏栽，兩株晴笑碧岩隈。枉教絕世深紅色，',40,'御定全唐詩/json/884.json','["不向橫塘泥裏栽，兩株晴笑碧岩隈。枉教絕世深紅色，", "緣花更歎人間事，半日江邊悵望回。"]'),
('yuding-46','新柳','崔櫓','唐','御定全唐诗','yuding','','[]','無情柔態任春催，似不勝風倚古台。',32,'御定全唐詩/json/884.json','["無情柔態任春催，似不勝風倚古台。", "多少去年今日恨，禦溝顏色洞庭來。"]'),
('yuding-47','臨川見新柳','崔櫓','唐','御定全唐诗','yuding','','[]','不見江頭三四日，橋邊楊柳老金絲。岸南岸北往來渡，',40,'御定全唐詩/json/884.json','["不見江頭三四日，橋邊楊柳老金絲。岸南岸北往來渡，", "汀洲草色亦如此，愁殺遠人人不知。"]'),
('yuding-48','南陽見柳','崔櫓','唐','御定全唐诗','yuding','','[]','夜來風入最高枝，罥斷愁腸幾尺絲。楚塞曾吟煙午處，',40,'御定全唐詩/json/884.json','["夜來風入最高枝，罥斷愁腸幾尺絲。楚塞曾吟煙午處，", "還把舊年惆悵意，武安城下一吟詩。"]'),
('yuding-49','別君山','崔櫓','唐','御定全唐诗','yuding','','[]','點空誇黛妒愁眉，何必浮來結夢思。',32,'御定全唐詩/json/884.json','["點空誇黛妒愁眉，何必浮來結夢思。", "慚愧二年青翠色，惹窗粘枕伴吟詩。"]'),
('yuding-50','宿壽安山陰館聞泉','崔櫓','唐','御定全唐诗','yuding','','[]','一支清急萬山來，穿竹喧飛破石苔。夢在故鄉臨欲到，',40,'御定全唐詩/json/884.json','["一支清急萬山來，穿竹喧飛破石苔。夢在故鄉臨欲到，", "緣憶舊遊相似處，月明山響子陵台。"]'),
('yuding-51','共佳人守歲','劉綺莊','唐','御定全唐诗','yuding','','[]','桂華窮北陸，荊豔作東鄰。殘妝欲送曉，薄衣已迎春。',48,'御定全唐詩/json/884.json','["桂華窮北陸，荊豔作東鄰。殘妝欲送曉，薄衣已迎春。", "舉袖爭流雪，分歌競繞塵。不應將共醉，年去遠催人。"]'),
('yuding-0','櫻桃花','皮日休','唐','御定全唐诗','yuding','','[]','婀娜枝香拂酒壺，向陽疑是不融酥。',32,'御定全唐詩/json/885.json','["婀娜枝香拂酒壺，向陽疑是不融酥。", "晚來嵬峨渾如醉，惟有春風獨自扶。"]'),
('yuding-1','夜看櫻桃花','皮日休','唐','御定全唐诗','yuding','','[]','纖枝瑤月弄圓霜，半入鄰家半入牆。',32,'御定全唐詩/json/885.json','["纖枝瑤月弄圓霜，半入鄰家半入牆。", "劉阮不知人獨立，滿衣清露到明香。"]'),
('yuding-2','詠白蓮','皮日休','唐','御定全唐诗','yuding','','[]','膩于瓊粉白於脂，京兆夫人未畫眉。靜婉舞偷將動處，',80,'御定全唐詩/json/885.json','["膩于瓊粉白於脂，京兆夫人未畫眉。靜婉舞偷將動處，", "願作水仙無別意，年年圖與此花期。", "細嗅深看暗斷腸，從今無意愛紅芳。折來隻合瓊為客，", "吳王台下開多少，遙似西施上素妝。"]'),
('yuding-3','赤門堰白蓮花','皮日休','唐','御定全唐诗','yuding','','[]','縞帶與綸巾，輕舟漾赤門。千回紫萍岸，萬頃白蓮村。',48,'御定全唐詩/json/885.json','["縞帶與綸巾，輕舟漾赤門。千回紫萍岸，萬頃白蓮村。", "荷露傾衣袖，松風入髻根。瀟疏今若此，爭不盡餘尊。"]'),
('yuding-4','丙午歲旦','司空圖','唐','御定全唐诗','yuding','','[]','雞報已判春，中年抱疾身。曉催庭火暗，風帶寺幡新。',48,'御定全唐詩/json/885.json','["雞報已判春，中年抱疾身。曉催庭火暗，風帶寺幡新。", "多慮無成事，空休是吉人。梅花浮壽酒，莫笑又移巡。"]'),
('yuding-5','丁巳元日','司空圖','唐','御定全唐诗','yuding','','[]','稟朔華夷會，開春氣象生。日隨行闕近，岳為壽觴晴。',240,'御定全唐詩/json/885.json','["稟朔華夷會，開春氣象生。日隨行闕近，岳為壽觴晴。", "作睿由稽古，昭仁事措刑。上玄勞眷佑，高廟保忠貞。", "星變當移幸，人心喜奉迎。傳呼清禦道，雪涕識臣誠。", "鼎飪和方濟，臺階潤欲平。扶天咨協力，並日召延英。", "金躍洪爐動，雲驅眾蟄驚。關中留王氣，席上縱奇兵。", "累降搜賢詔，兼持進善旌。短轅收驥步，直路發鵬程。", "自乏匡時略，非沽矯俗名。鶴籠何足獻，蝸舍別無營。", "羸帶漳濱病，吟哀越客聲。移居荒藥圃，耗志在棋枰。", "醉忘身空老，書憐眼尚明。偶能甘蹇分，豈是薄浮榮。", "慮戒防微淺，□知近利輕。獻陵三百里，寤寐禱時清。"]'),
('yuding-6','光啟三年人日逢鹿','司空圖','唐','御定全唐诗','yuding','','[]','浮世仍逢亂，安排賴佛書。勞生中壽少，抱疾上升疏。',48,'御定全唐詩/json/885.json','["浮世仍逢亂，安排賴佛書。勞生中壽少，抱疾上升疏。", "日暖人逢鹿，園荒雪帶鋤。知非今又過，蘧瑗最憐渠。"]'),
('yuding-7','浙上重陽','司空圖','唐','御定全唐诗','yuding','','[]','登高唯北望，菊助可□明。離恨初逢節，貧居只喜晴。',48,'御定全唐詩/json/885.json','["登高唯北望，菊助可□明。離恨初逢節，貧居只喜晴。", "好文時可見，學稼老無成。莫歎關山阻，何當不阻兵。"]'),
('yuding-8','乙巳歲愚春秋四十九辭疾拜章將免左掖重陽獨登上方','司空圖','唐','御定全唐诗','yuding','','[]','雪鬢不禁鑷，知非又此年。退居還有旨，榮路免妨賢。',48,'御定全唐詩/json/885.json','["雪鬢不禁鑷，知非又此年。退居還有旨，榮路免妨賢。", "落落鳴蛩鳥，晴霞度雁天。自無佳節興，依舊菊籬邊。"]'),
('yuding-9','重陽山居','司空圖','唐','御定全唐诗','yuding','','[]','此身逃難入鄉關，八度重陽在舊山。籬菊亂來成爛熳，',40,'御定全唐詩/json/885.json','["此身逃難入鄉關，八度重陽在舊山。籬菊亂來成爛熳，", "滿目秋光還似鏡，殷勤為我照衰顏。"]'),
('yuding-10','旅中重陽','司空圖','唐','御定全唐诗','yuding','','[]','乘時爭路只危身，經亂登高有幾人。今歲節唯南至在，',40,'御定全唐詩/json/885.json','["乘時爭路只危身，經亂登高有幾人。今歲節唯南至在，", "莫道中冬猶有閏，蟾聲才盡即青春。"]'),
('yuding-11','南至日','司空圖','唐','御定全唐诗','yuding','','[]','年年山□□來頻，莫強孤危競要津。吉卦偶成開病眼，',40,'御定全唐詩/json/885.json','["年年山□□來頻，莫強孤危競要津。吉卦偶成開病眼，", "鬢髮堪傷白已遍，鏡中更待白眉新。"]'),
('yuding-12','五月九日','司空圖','唐','御定全唐诗','yuding','','[]','金石皆銷鑠，賢愚共網羅。達從詩似偈，狂覺哭勝歌。',48,'御定全唐詩/json/885.json','["金石皆銷鑠，賢愚共網羅。達從詩似偈，狂覺哭勝歌。", "高燕淩鴻鵠，枯槎壓芰荷。此中無別境，此外是閑魔。"]'),
('yuding-13','庚子臘月五日','司空圖','唐','御定全唐诗','yuding','','[]','複道朝延火，嚴城夜漲塵。驊騮思故第，鸚鵡失佳人。',48,'御定全唐詩/json/885.json','["複道朝延火，嚴城夜漲塵。驊騮思故第，鸚鵡失佳人。", "禁漏虛傳點，妖星不振辰。何當回萬乘，重睹玉京春。"]'),
('yuding-14','中元夜看月','羅隱','唐','御定全唐诗','yuding','','[]','朦朧南溟月，洶湧出雲濤。下射長鯨眼，遙分玉兔毫。',48,'御定全唐詩/json/885.json','["朦朧南溟月，洶湧出雲濤。下射長鯨眼，遙分玉兔毫。", "勢來牛鬥動，路越宵冥高。竟夕瞻光影，昂頭把白醪。"]'),
('yuding-15','木蘭','唐彥謙','唐','御定全唐诗','yuding','','[]','眾花搖落正無憀，脈脈芳叢契後凋。舒卷綠苞臨小檻，',40,'御定全唐詩/json/885.json','["眾花搖落正無憀，脈脈芳叢契後凋。舒卷綠苞臨小檻，", "桃葉近來消息絕，見君長憶渡江橈。"]'),
('yuding-16','玉蕊','唐彥謙','唐','御定全唐诗','yuding','','[]','玉蕊兩高樹，相輝松桂旁。向來塵不雜，此夜月仍光。',48,'御定全唐詩/json/885.json','["玉蕊兩高樹，相輝松桂旁。向來塵不雜，此夜月仍光。", "秀掩叢蘭色，豔吞穠李芳。世人嫌具美，何必更清香。"]'),
('yuding-17','蓮','唐彥謙','唐','御定全唐诗','yuding','','[]','新蓮映多浦，迢遞綠塘東。靜影搖波日，寒香映水風。',48,'御定全唐詩/json/885.json','["新蓮映多浦，迢遞綠塘東。靜影搖波日，寒香映水風。", "金塵飄落蕊，玉露洗殘紅。看著餘芳少，無人問的中。"]'),
('yuding-18','望岳時賊據華夏','唐彥謙','唐','御定全唐诗','yuding','','[]','長路風埃隔楚氛，忽驚神嶽映朝曛。削成絕壁五千仞，',40,'御定全唐詩/json/885.json','["長路風埃隔楚氛，忽驚神嶽映朝曛。削成絕壁五千仞，", "幽人閑望封中地，好為吾皇起白雲。"]'),
('yuding-19','片石','唐彥謙','唐','御定全唐诗','yuding','','[]','小齋廬阜石，寄自沃洲僧。山客勞攜笈，幽人自得朋。',48,'御定全唐詩/json/885.json','["小齋廬阜石，寄自沃洲僧。山客勞攜笈，幽人自得朋。", "瘦雲低作段，野浪凍成雲。便可同清話，何須有物憑。"]'),
('yuding-20','柳','唐彥謙','唐','御定全唐诗','yuding','','[]','春風向楊柳，能事盡風流。有意疑張緒，無情見莫愁。',48,'御定全唐詩/json/885.json','["春風向楊柳，能事盡風流。有意疑張緒，無情見莫愁。", "依然金谷在，甯免武昌偷。前路難回首，何須苦映樓。"]'),
('yuding-21','垂柳','唐彥謙','唐','御定全唐诗','yuding','','[]','垂柳碧髯茸，樓昏帶雨容。思量成晝夢，來去發春慵。',96,'御定全唐詩/json/885.json','["垂柳碧髯茸，樓昏帶雨容。思量成晝夢，來去發春慵。", "梳洗憑張敞，乘騎笑稚恭。碧虛從轉笠，紅燭近高舂。", "怨臉明秋水，愁眉淡遠峰。小園花盡蝶，靜院酒醒蛩。", "舊作琴台鳳，今為藥店龍。寶奩拋擲久，一任景陽鐘。"]'),
('yuding-22','紫薇花','唐彥謙','唐','御定全唐诗','yuding','','[]','素秋寒露重，芳事固應稀。小檻臨清昭，高叢見紫薇。',121,'御定全唐詩/json/885.json','["素秋寒露重，芳事固應稀。小檻臨清昭，高叢見紫薇。", "溫r3終有思，暗淡豈無輝。見欲迷交甫，誰能狀宓妃。", "妝新猶倚鏡，步緩不勝衣。恍似新相得，倀如久未歸。", "又疑神女過，猶佩七香幃。還似星娥織，初臨五彩機。", "慶雲今已集，威鳳莫驚飛。綺筆題難盡，煩君白玉徽。"]'),
('yuding-23','望中條','唐彥謙','唐','御定全唐诗','yuding','','[]','虞鄉縣西郭，改觀揖中條。第蓄終南小，交□□□遙。',48,'御定全唐詩/json/885.json','["虞鄉縣西郭，改觀揖中條。第蓄終南小，交□□□遙。", "崦深應有寺，峰近恐通橋。為語前村叟，他時寄采樵。"]'),
('yuding-24','蒙谷山','唐彥謙','唐','御定全唐诗','yuding','','[]','蒙谷山低碧海枯，仲君閑坐說麻姑。遙天鶴語知虛實，',40,'御定全唐詩/json/885.json','["蒙谷山低碧海枯，仲君閑坐說麻姑。遙天鶴語知虛實，", "交朋漫信文成術，短燭瑤壇漏滿壺。"]'),
('yuding-25','菊','唐彥謙','唐','御定全唐诗','yuding','','[]','雪菊金英兩斷腸，蝶翎蜂鼻帶清香。寒村宿霧臨幽徑，',40,'御定全唐詩/json/885.json','["雪菊金英兩斷腸，蝶翎蜂鼻帶清香。寒村宿霧臨幽徑，", "年來病肺疏杯酒，每憶龍山似故鄉。"]'),
('yuding-26','山中','方幹','唐','御定全唐诗','yuding','','[]','愛山卻把圖書賣，嗜酒空教僮僕賒。只向階前便漁釣，',48,'御定全唐詩/json/885.json','["愛山卻把圖書賣，嗜酒空教僮僕賒。只向階前便漁釣，", "窗竹未抽今夏筍，庭梅曾試當年花。姓名未及陶弘景，"]'),
('yuding-27','次韻和盧先輩避難寺居看牡丹','王駕','唐','御定全唐诗','yuding','','[]','亂後寄僧居，看花恨有餘。香宜閒靜立，態似別離初。',48,'御定全唐詩/json/885.json','["亂後寄僧居，看花恨有餘。香宜閒靜立，態似別離初。", "朵密紅相照，欄低畫不如。狂風任吹卻，最共野人疏。"]'),
('yuding-28','春宮怨','杜荀鶴','唐','御定全唐诗','yuding','','[]','早被嬋娟誤，欲妝臨鏡慵。承恩不在貌，教妾若為容。',48,'御定全唐詩/json/885.json','["早被嬋娟誤，欲妝臨鏡慵。承恩不在貌，教妾若為容。", "風暖鳥聲碎，日高花影重。年年越溪女，相憶采芙蓉。"]'),
('yuding-29','晨興','翁承贊','唐','御定全唐诗','yuding','','[]','鼓絕天街冷霧收，曉來風景已堪愁。槐無顏色因經雨，',40,'御定全唐詩/json/885.json','["鼓絕天街冷霧收，曉來風景已堪愁。槐無顏色因經雨，", "披襟徐步一蕭灑，吟繞盆池想狎鷗。"]'),
('yuding-30','江上吟曉','王貞白','唐','御定全唐诗','yuding','','[]','一葉野人舟，長將載酒遊。夜來吟思苦，江上月華秋。',48,'御定全唐詩/json/885.json','["一葉野人舟，長將載酒遊。夜來吟思苦，江上月華秋。", "曉露滿紅蓼，輕波颺白鷗。漁翁似有約，相伴釣中流。"]'),
('yuding-31','過商山','王貞白','唐','御定全唐诗','yuding','','[]','一宿白雲根，時經采麝村。數峰雖似蜀，當晝不聞猿。',48,'御定全唐詩/json/885.json','["一宿白雲根，時經采麝村。數峰雖似蜀，當晝不聞猿。", "馬立溪沙淺，人爭閣道喧。明朝棄襦罷，步步入金門。"]'),
('yuding-32','泛鏡湖□□','王貞白','唐','御定全唐诗','yuding','','[]','我泛鏡湖日，未生千里蓴。時無賀賓客，誰識謫仙人。',48,'御定全唐詩/json/885.json','["我泛鏡湖日，未生千里蓴。時無賀賓客，誰識謫仙人。", "吟對四時雪，憶遊三島春。惡聞亡越事，洗耳大江濱。"]'),
('yuding-33','太湖石','王貞白','唐','御定全唐诗','yuding','','[]','誰憐孤峭質，移在太湖心。出得風波外，任他池館深。',48,'御定全唐詩/json/885.json','["誰憐孤峭質，移在太湖心。出得風波外，任他池館深。", "不同花逞豔，多愧竹垂陰。一片至堅操，那憂歲月侵。"]'),
('yuding-34','依韻和幹公題庭中太湖石二首','王貞白','唐','御定全唐诗','yuding','','[]','山立只盈尋，高奇藥圃陰。風濤打欲碎，岩穴蟄方深。',96,'御定全唐詩/json/885.json','["山立只盈尋，高奇藥圃陰。風濤打欲碎，岩穴蟄方深。", "蘚點晴偏綠，蛩藏曉競吟。歲寒終不變，堪比古人心。", "徒勞水府尋，宛在玉堂陰。蘭圃安雖窄，盆池映轉深。", "山僧來盡愛，詩客見先吟。若是買花者，年年不計心。"]'),
('yuding-35','書陶潛醉石','王貞白','唐','御定全唐诗','yuding','','[]','片石陶真性，非為麹糵昏。爭如累月醉，不笑獨醒人。',48,'御定全唐詩/json/885.json','["片石陶真性，非為麹糵昏。爭如累月醉，不笑獨醒人。", "積疊莓苔色，交加薜荔根。至今重九日，猶待白衣魂。"]');
